[patch.'https://github.com/Starry-Mix-THU/axsignal.git']
axsignal = { path = "vendor/axsignal" }

[patch.crates-io]
# 使用本地 vendor 副本，避免修改后的 vendored crate 继续触发 checksum 校验。
sbi-spec = { path = "vendor/sbi-spec" }
clang-sys = { path = "vendor/clang-sys" }
loongArch64 = { path = "vendor/loongArch64" }
page_table_entry = { path = "vendor/page_table_entry" }
page_table_multiarch = { path = "vendor/page_table_multiarch" }
proc-macro-error2 = { path = "vendor/proc-macro-error2" }
zerocopy = { path = "vendor/zerocopy" }

[package.metadata.vendor-filter]
platforms = ["riscv64gc-unknown-none-elf", "loongarch64-unknown-none"]

//! Starry Mix OS 内核入口点
//!
//! 本文件是操作系统的主入口，负责初始化内核环境、挂载文件系统、
//! 并启动用户态的 init 进程来运行测试脚本。

// ============================================================================
// 全局属性配置
// ============================================================================

#![no_std]
// 禁用标准库链接。
// 内核运行在裸机环境，没有操作系统支持，因此无法使用 std（文件系统、线程等）。
// 只能使用 core 库（基本类型、运算等无 OS 依赖的功能）。

#![no_main]
// 禁用标准 main() 入口。
// 内核由 ArceOS runtime (axruntime) 提供启动流程，从汇编入口直接跳转到 Rust。
// 标准的 std::rt::lang_start 包装器不存在。

#![doc = include_str!("../README.md")]
// 将 README.md 内容作为 crate 文档首页。
// 运行 `cargo doc` 时，生成的文档首页会显示 README 内容。

// ============================================================================
// 外部 crate 声明
// ============================================================================

#[macro_use]
extern crate axlog;
// 引入 axlog 日志库，并导入其宏（如 info!, warn!, error! 等）。
// #[macro_use] 使得这些宏在当前模块及其子模块中可直接使用。

extern crate alloc;
// 引入 alloc 库，提供动态内存分配功能。
// 包含 String、Vec、Box、Arc 等堆分配类型。
// 注意：alloc 需要#[global_allocator] 提供，在 axalloc 模块中配置。

extern crate axruntime;
// 引入 ArceOS 运行时库。
// 提供内核启动流程：从汇编入口 → axruntime::init → 调用本文件的 main()。

// ============================================================================
// 导入依赖
// ============================================================================

use alloc::{format, string::ToString, vec::Vec};
use axfs_ng::FS_CONTEXT;
use axfs_ng_vfs::NodePermission;
// 从 alloc 库导入字符串相关工具。
// format! 用于格式化字符串，ToString trait 用于类型转字符串。

use starry_core::mm::insert_elf_cache;
// 导入 ELF 缓存插入函数。
// 用于预加载常用 ELF 文件到内存缓存，加速后续加载。

// ============================================================================
// 内部模块声明
// ============================================================================

mod entry;
// 用户态应用程序启动模块。
// 提供 run_user_app() 函数，负责加载 ELF、创建进程/线程、启动执行。

mod mm;
// 内存管理辅助模块。
// 处理内核态与用户态内存映射相关操作。

mod syscall;
// 系统调用处理模块。
// 用户态程序通过 syscall 请求内核服务（如 read、write、fork 等）。

// ============================================================================
// ELF 预缓存配置
// ============================================================================

/// 预缓存 ELF 文件列表（riscv64 架构）
///
/// 这些是启动测试脚本时频繁使用的 ELF 文件，预加载可避免重复解析：
/// - `/musl/busybox` - musl libc 版本的 busybox 工具集
/// - `/glibc/busybox` - glibc 版本的 busybox
/// - `/musl/lib/libc.so` - musl 动态链接器
/// - `/glibc/lib/ld-linux-riscv64-lp64d.so.1` - glibc 动态链接器
#[cfg(target_arch = "riscv64")]
const CACHED_ELFS: &[&str] = &[
    "/musl/busybox",
    "/glibc/busybox",
    "/musl/lib/libc.so",
    "/glibc/lib/ld-linux-riscv64-lp64d.so.1",
    // 中文注释：glibc libc.so.6 约 2MB，每次 fork+exec 时 ld-linux
    // 都要重新 open+read+mmap 它。启动时预读进内核缓冲区可以避免
    // 测试期间反复从 ext4 磁盘读取，显著降低 glibc 测例的冷启动开销。
    "/glibc/lib/libc.so.6",
    "/glibc/lib/libm.so.6",
    "/glibc/lib/libgcc_s.so.1",
];

/// 预缓存 ELF 文件列表（loongarch64 架构）
///
/// 与 riscv64 类似，但动态链接器名称不同：
/// - LoongArch 架构的 glibc 动态链接器路径不同
#[cfg(target_arch = "loongarch64")]
const CACHED_ELFS: &[&str] = &[
    "/musl/busybox",
    "/glibc/busybox",
    "/musl/lib/libc.so",
    "/glibc/lib/ld-linux-loongarch-lp64d.so.1",
    "/glibc/lib/libc.so.6",
    "/glibc/lib/libm.so.6",
    "/glibc/lib/libgcc_s.so.1",
];

#[cfg(target_arch = "riscv64")]
const EMBEDDED_LIBGCC_S_SO: &[u8] = include_bytes!("/usr/riscv64-linux-gnu/lib/libgcc_s.so.1");

#[cfg(target_arch = "loongarch64")]
const EMBEDDED_LIBGCC_S_SO: &[u8] = include_bytes!(
    "/opt/gcc-13.2.0-loongarch64-linux-gnu/loongarch64-linux-gnu/lib64/libgcc_s.so.1"
);

#[cfg(not(any(target_arch = "riscv64", target_arch = "loongarch64")))]
const EMBEDDED_LIBGCC_S_SO: &[u8] = &[];

fn ensure_libgcc_runtime() {
    // 中文注释：评测盘是系统提供的，不能直接修改；
    // 这里把当前架构的 `libgcc_s.so.1` 编进内核，并在 rootfs 挂好后立刻落盘。
    let fs = FS_CONTEXT.lock();
    if fs.metadata("/glibc/lib/libgcc_s.so.1").is_ok() {
        info!("libgcc_s.so.1 already exists in rootfs");
        return;
    }
    if EMBEDDED_LIBGCC_S_SO.is_empty() {
        warn!("embedded libgcc_s.so.1 is unavailable for current target");
        return;
    }
    // 中文注释：不同测试盘的目录布局不完全一致，这里把父目录补齐后再写文件，
    // 避免 `FsContext::write()` 因父目录不存在直接返回 `ENOENT`。
    if fs.metadata("/glibc").is_err() {
        fs.create_dir("/glibc", NodePermission::from_bits_truncate(0o755))
            .expect("failed to create /glibc");
    }
    if fs.metadata("/glibc/lib").is_err() {
        fs.create_dir("/glibc/lib", NodePermission::from_bits_truncate(0o755))
            .expect("failed to create /glibc/lib");
    }
    fs.write("/glibc/lib/libgcc_s.so.1", EMBEDDED_LIBGCC_S_SO)
        .expect("failed to install embedded libgcc_s.so.1");
    info!(
        "installed embedded libgcc_s.so.1 ({} bytes)",
        EMBEDDED_LIBGCC_S_SO.len()
    );
}

// ============================================================================
// 内核主函数
// ============================================================================

/// 内核主入口函数
///
/// 由 axruntime 在内核启动完成后调用。执行流程：
/// 1. 创建 init 进程（所有用户进程的父进程）
/// 2. 挂载虚拟文件系统（VFS）
/// 3. 预缓存常用 ELF 文件
/// 4. 运行 init.sh 脚本启动测试套件
///
/// 注意：此函数不会返回，内核持续运行直到系统关闭。
#[unsafe(no_mangle)]
fn main() {
    // -------------------------------------------------------------------------
    // 步骤 1：创建 init 进程
    // -------------------------------------------------------------------------
    // 创建 PID=当前任务ID 的初始进程，作为所有用户态进程的父进程。
    // init 进程是 Unix 系统的传统，负责启动其他系统服务。
    axprocess::Process::new_init(axtask::current().id().as_u64() as _).build();

    // -------------------------------------------------------------------------
    // 步骤 2：挂载文件系统
    // -------------------------------------------------------------------------
    // 挂载所有配置的文件系统：
    // - 根文件系统（ext4 格式的测试磁盘）
    // - procfs（进程信息）
    // - tmpfs（临时文件）
    // 如果挂载失败，内核无法继续运行，直接 panic。
    starry_core::vfs::mount_all().expect("Failed to mount vfs");
    ensure_libgcc_runtime();

    // -------------------------------------------------------------------------
    // 步骤 3：设置环境变量
    // -------------------------------------------------------------------------
    // 设置传给 init.sh 的环境变量。
    // ARCH 用于区分架构；LTP_CASES 用于在 make 层选择只跑哪些测试项。
    let mut envs = Vec::with_capacity(2);
    envs.push(format!("ARCH={}", option_env!("ARCH").unwrap_or("unknown")));
    if let Some(cases) = option_env!("LTP_CASES") {
        if !cases.is_empty() {
            envs.push(format!("LTP_CASES={cases}"));
        }
    }

    // -------------------------------------------------------------------------
    // 步骤 4：读取 init 脚本
    // -------------------------------------------------------------------------
    // 在编译时将 init.sh 内容嵌入内核二进制。
    // init.sh 包含测试套件启动命令：
    // - LTP 测试（300+ syscall 测试）
    // - busybox 测试
    // - iozone/lmbench 性能测试
    let init = include_str!("init.sh")
        .replace("__RV_LTP_CASES__", include_str!("rv_case"))
        .replace("__LA_LTP_CASES__", include_str!("la_case"));

    // -------------------------------------------------------------------------
    // 步骤 5：预缓存 ELF 文件
    // -------------------------------------------------------------------------
    // 将常用 ELF 文件解析结果缓存到内存。
    // 避免每次执行 busybox/sh 时重新解析 ELF 头，加速启动。
    for elf in CACHED_ELFS {
        // 中文注释：这里的预缓存只是启动优化，个别文件缺失不应该直接把整机拉死。
        // 特别是不同测试盘的布局略有差异时，先打印告警并继续进入真正的功能测试。
        if let Err(err) = insert_elf_cache(elf) {
            warn!("skip elf cache for {elf}: {:?}", err);
        }
    }

    // -------------------------------------------------------------------------
    // 步骤 6：执行 init 脚本
    // -------------------------------------------------------------------------
    // 使用 busybox sh 解释执行 init.sh。
    // run_user_app() 创建新的用户态进程，加载 ELF，设置上下文，启动执行。
    info!("Running init script");
    let args = ["/musl/busybox", "sh", "-c", &init]
        .map(|s| s.to_string())
        .to_vec();
    let exit_code = entry::run_user_app(&args, &envs);

    // -------------------------------------------------------------------------
    // 步骤 7：报告执行结果
    // -------------------------------------------------------------------------


