use alloc::{borrow::ToOwned, string::String, sync::Arc};
use axfs_ng::FS_CONTEXT;
use axhal::arch::UspaceContext;
use axprocess::{Pid, init_proc};
use axsignal::Signo;
use axsync::Mutex;
use axtask::TaskExtProxy;
use starry_core::{
    mm::{copy_from_kernel, load_user_app, map_trampoline, new_user_aspace_empty},
    task::{ProcessData, StarryTaskExt, ThreadData, add_thread_to_table, new_user_task},
};

pub fn run_user_app(args: &[String], envs: &[String]) -> Option<i32> {
    let mut uspace = new_user_aspace_empty()
        .and_then(|mut it| {
            copy_from_kernel(&mut it)?;
            map_trampoline(&mut it)?;
            Ok(it)
        })
        .expect("Failed to create user address space");

    let exe_path = &args[0];
    let name = FS_CONTEXT
        .lock()
        .resolve(exe_path)
        .expect("Failed to resolve executable path")
        .name()
        .to_owned();

    let (entry_vaddr, ustack_top) = load_user_app(&mut uspace, None, args, envs)
        .unwrap_or_else(|e| panic!("Failed to load user app: {}", e));

    let uctx = UspaceContext::new(entry_vaddr.into(), ustack_top, 2333);

    let mut task = new_user_task(&name, uctx, None);
    task.ctx_mut().set_page_table_root(uspace.page_table_root());

    let process_data = ProcessData::new(
        exe_path.clone(),
        Arc::new(Mutex::new(uspace)),
        Arc::default(),
        Some(Signo::SIGCHLD),
    );

    let tid = task.id().as_u64() as Pid;
    let process = init_proc().fork(tid).data(process_data).build();

    let thread = process
        .new_thread(tid)
        .data(ThreadData::new(process.data().unwrap()))
        .build();
    add_thread_to_table(&thread);

    *task.task_ext_mut() = Some(unsafe { TaskExtProxy::from_impl(StarryTaskExt::new(thread)) });

    let task = axtask::spawn_task(task);
    StarryTaskExt::of(&task)
        .thread_data()
        .init_task(|| Arc::downgrade(&task));

    // TODO: we need a way to wait on the process but not only the main task
    task.join()
}

use axhal::{
    mem::VirtAddr,
    paging::MappingFlags,
    trap::{PAGE_FAULT, register_trap_handler},
};
use axsignal::{SignalInfo, Signo};
use axtask::current;
use linux_raw_sys::general::{RLIMIT_STACK, SI_KERNEL};
use starry_api::signal::send_signal_process;
use starry_core::{mm::is_accessing_user_memory, task::StarryTaskExt};

fn handle_user_page_fault(
    ext: &StarryTaskExt,
    vaddr: VirtAddr,
    access_flags: MappingFlags,
) -> bool {
    if (starry_config::USER_STACK_TOP - starry_config::USER_STACK_SIZE
        ..starry_config::USER_STACK_TOP)
        .contains(&vaddr.as_usize())
    {
        // Stack extension, check rlimit
        let rlim = &ext.process_data().rlim.read()[RLIMIT_STACK];
        let size = starry_config::USER_STACK_TOP - vaddr.as_usize();
        if size as u64 > rlim.current {
            return false;
        }
    }
    ext.process_data()
        .aspace
        .lock()
        .handle_page_fault(vaddr, access_flags)
}

#[register_trap_handler(PAGE_FAULT)]
fn handle_page_fault(vaddr: VirtAddr, access_flags: MappingFlags, is_user: bool) -> bool {
    debug!(
        "Page fault at {:#x}, access_flags: {:#x?}",
        vaddr, access_flags
    );
    // 中文注释：COW 开启后，内核在 syscall 流程里写用户地址时可能会碰到
    // 被 COW 标为只读的页。这时 `is_accessing_user_memory()` 不一定被设置，
    // 但仍然需要走 COW 处理，否则直接 panic。
    // 这里只在访问的是内核地址且确实不在用户内存访问上下文时才拒绝。
    if !is_user
        && !is_accessing_user_memory()
        && (vaddr < VirtAddr::from(starry_config::USER_SPACE_BASE)
            || vaddr >= VirtAddr::from(
                starry_config::USER_SPACE_BASE + starry_config::USER_SPACE_SIZE,
            ))
    {
        return false;
    }

    let curr = current();
    let ext = StarryTaskExt::of(&curr);

    if !handle_user_page_fault(ext, vaddr, access_flags) {
        // 中文注释：这里不要再打印任务名字符串。
        // 当前 `splice02` 崩溃现场里，怀疑任务名或相关字符串元数据已经被破坏，
        // 若继续走 `curr.id_name()` 的 `{:?}` 格式化，可能在 `core::fmt`
        // 里再次 panic，把真正的首个页错误现场覆盖掉。
        warn!(
            "segmentation fault: task_id={}, tid={}, pid={}, fault_vaddr={:#x}",
            curr.id().as_u64(),
            ext.thread.tid(),
            ext.thread.process().pid(),
            vaddr
        );
        send_signal_process(
            ext.thread.process(),
            SignalInfo::new(Signo::SIGSEGV, SI_KERNEL as _),
        )
        .expect("Failed to send SIGSEGV");
    }

    true
}

