/// Creates a new empty user address space.
pub fn new_user_aspace_empty() -> AxResult<AddrSpace> {
    AddrSpace::new_empty(
        VirtAddr::from_usize(starry_config::USER_SPACE_BASE),
        starry_config::USER_SPACE_SIZE,
    )
}

/// If the target architecture requires it, the kernel portion of the address
/// space will be copied to the user address space.
pub fn copy_from_kernel(_aspace: &mut AddrSpace) -> AxResult {
    #[cfg(not(any(target_arch = "aarch64", target_arch = "loongarch64")))]
    {
        // ARMv8 (aarch64) and LoongArch64 use separate page tables for user space
        // (aarch64: TTBR0_EL1, LoongArch64: PGDL), so there is no need to copy the
        // kernel portion to the user page table.
        _aspace.copy_mappings_from(&axmm::kernel_aspace().lock())?;
    }
    Ok(())
}

/// Map the signal trampoline to the user address space.
pub fn map_trampoline(aspace: &mut AddrSpace) -> AxResult {
    let signal_trampoline_paddr = virt_to_phys(axsignal::arch::signal_trampoline_address().into());
    aspace.map_linear(
        starry_config::SIGNAL_TRAMPOLINE.into(),
        signal_trampoline_paddr,
        PAGE_SIZE_4K,
        MappingFlags::READ | MappingFlags::EXECUTE | MappingFlags::USER,
        PageSize::Size4K,
    )?;
    Ok(())
}

/// Map the elf file to the user address space.
///
/// # Arguments
/// - `uspace`: The address space of the user app.
/// - `elf`: The elf file.
///
/// # Returns
/// - The entry point of the user app.
fn map_elf<'a>(uspace: &mut AddrSpace, base: usize, elf: &'a ElfFile, file_key: (u64, u64)) -> AxResult<ELFParser<'a>> {
    let elf_parser = ELFParser::new(elf, base).map_err(|_| AxError::InvalidData)?;
    let use_cache = ENABLE_TEXT_CACHE.load(Ordering::Relaxed);

    for segement in elf_parser.ph_load() {
        let seg_pad = segement.vaddr.align_offset_4k();
        assert_eq!(seg_pad, segement.offset % PAGE_SIZE_4K);
        let seg_align_size =
            (segement.memsz as usize + seg_pad + PAGE_SIZE_4K - 1) & !(PAGE_SIZE_4K - 1);
        let is_text = use_cache
            && !segement.flags.contains(MappingFlags::WRITE)
            // fs_bind 会高频拉起大量短命 glibc helper；过高门槛会让不少
            // 小型 ELF text 段完全吃不到缓存，这里降到 4 页让批量跑更容易复用。
            && seg_align_size >= TEXT_CACHE_MIN_SEG_SIZE;

        if is_text {
            let cache_key = (file_key.0, file_key.1, segement.offset, seg_align_size);
            if let Some(cached) = TEXT_PAGE_CACHE.read().get(&cache_key) {
                uspace.map_shared(
                    segement.vaddr.align_down_4k(), seg_align_size,
                    segement.flags, Some(cached.clone()), PageSize::Size4K,
                )?;
                continue;
            }
            let pages = uspace.map_shared(
                segement.vaddr.align_down_4k(), seg_align_size,
                segement.flags, None, PageSize::Size4K,
            )?;
            let seg_data = elf.input
                .get(segement.offset..segement.offset + segement.filesz as usize)
                .ok_or(AxError::InvalidData)?;
            uspace.write(segement.vaddr, PageSize::Size4K, seg_data)?;
            TEXT_PAGE_CACHE.write().insert(cache_key, pages);
            continue;
        }
        uspace.map_alloc(
            segement.vaddr.align_down_4k(), seg_align_size,
            segement.flags, true, PageSize::Size4K,
        )?;
        let seg_data = elf.input
            .get(segement.offset..segement.offset + segement.filesz as usize)
            .ok_or(AxError::InvalidData)?;
        uspace.write(segement.vaddr, PageSize::Size4K, seg_data)?;
        #[cfg(target_arch = "loongarch64")]
        axhal::arch::flush_icache_all();
    }
    Ok(elf_parser)
}

/// ELF 只读 text 段物理页缓存。仅在 `ENABLE_TEXT_CACHE` 打开时生效。
static TEXT_PAGE_CACHE: RwLock<BTreeMap<(u64, u64, usize, usize), Arc<SharedPages>>> =
    RwLock::new(BTreeMap::new());
const TEXT_CACHE_MIN_SEG_SIZE: usize = PAGE_SIZE_4K * 4;

/// 清空 text 页缓存，释放所有缓存的物理页面。
pub fn clear_text_cache() {
    TEXT_PAGE_CACHE.write().clear();
}

static CACHED_ELF: RwLock<BTreeMap<usize, Arc<ElfFile>>> = RwLock::new(BTreeMap::new());
static CACHED_ELF_DATA: Mutex<Vec<(usize, usize)>> = Mutex::new(Vec::new());

/// Clears the cached ELF files and frees the underlying file data.
pub fn clear_elf_cache() {
    CACHED_ELF.write().clear();
    for (ptr, len) in CACHED_ELF_DATA.lock().drain(..) {
        let slice = unsafe { Box::from_raw(core::ptr::slice_from_raw_parts_mut(ptr as *mut u8, len)) };
        drop(slice);
    }
}

/// Inserts an ELF file into the cache.
pub fn insert_elf_cache(path: &str) -> LinuxResult<()> {
    let fs = FS_CONTEXT.lock();
    let loc = fs.resolve(path)?;
    let file_data: Box<[u8]> = fs.read(path)?.into_boxed_slice();
    let len = file_data.len();
    let ptr = Box::into_raw(file_data);
    CACHED_ELF_DATA.lock().push((ptr as *mut u8 as usize, len));
    let leaked: &'static [u8] =
        unsafe { &*core::ptr::slice_from_raw_parts(ptr as *const u8, len) };
    let elf = ElfFile::new(leaked).map_err(|_| LinuxError::ENOEXEC)?;
    CACHED_ELF
        .write()
        .insert(loc.entry().as_ptr(), Arc::new(elf));
    Ok(())
}

