fn check_exec_permission(mode: NodePermission, uid: u32, gid: u32, euid: u32, egid: u32) -> LinuxResult<()> {
    let mode_bits = mode.bits();

    // 中文注释：`execve()` 这里按 Linux 的执行权限语义做最小检查：
    // root 也至少需要 owner/group/other 任一执行位存在。
    if euid == 0 {
        let any_exec = NodePermission::OWNER_EXEC.bits()
            | NodePermission::GROUP_EXEC.bits()
            | NodePermission::OTHER_EXEC.bits();
        return if (mode_bits & any_exec) != 0 {
            Ok(())
        } else {
            Err(LinuxError::EACCES)
        };
    }

    let required = if euid == uid {
        NodePermission::OWNER_EXEC.bits()
    } else if egid == gid {
        NodePermission::GROUP_EXEC.bits()
    } else {
        NodePermission::OTHER_EXEC.bits()
    };

    if (mode_bits & required) != 0 {
        Ok(())
    } else {
        Err(LinuxError::EACCES)
    }
}

pub fn sys_execve(
    tf: &mut TrapFrame,
    path: UserConstPtr<c_char>,
    argv: UserConstPtr<UserConstPtr<c_char>>,
    envp: UserConstPtr<UserConstPtr<c_char>>,
) -> LinuxResult<isize> {
    let path = path.get_as_str()?.to_string();

    let args = nullable!(argv.get_as_null_terminated())?
        .unwrap_or(&[])
        .iter()
        .map(|arg| arg.get_as_str().map(Into::into))
        .collect::<Result<Vec<_>, _>>()?;
    let envs = nullable!(envp.get_as_null_terminated())?
        .unwrap_or(&[])
        .iter()
        .map(|env| env.get_as_str().map(Into::into))
        .collect::<Result<Vec<_>, _>>()?;

    let curr = current();
    let ext = StarryTaskExt::of(&curr);

    if ext.thread.process().threads().len() > 1 {
        // TODO: handle multi-thread case
        error!("sys_execve: multi-thread not supported");
        return Err(LinuxError::EAGAIN);
    }

    let metadata = FS_CONTEXT.lock().resolve(path.as_str())?.metadata()?;
    check_exec_permission(
        metadata.mode,
        metadata.uid,
        metadata.gid,
        ext.process_data().euid.load(core::sync::atomic::Ordering::Relaxed),
        ext.process_data().egid.load(core::sync::atomic::Ordering::Relaxed),
    )?;

    // 中文注释：`execve()` 失败时必须保留旧地址空间，不能像成功路径那样
    // 先拆掉当前进程镜像，否则用户态拿到错误码后已经没有原程序可返回了。
    let mut new_aspace = new_user_aspace_empty()?;
    copy_from_kernel(&mut new_aspace)?;
    map_trampoline(&mut new_aspace)?;
    let (entry_point, user_stack_base) =
        load_user_app(&mut new_aspace, Some(&path), &args, &envs).map_err(|err| {
            error!("Failed to load app {path}: {err:?}");
            err
        })?;

    let new_root = new_aspace.page_table_root();
    let mut aspace = ext.process_data().aspace.lock();
    // 中文注释：加载全部成功后再一次性切换页表根并替换进程地址空间。
    unsafe { curr.set_page_table_root(new_root) };
    #[cfg(target_arch = "loongarch64")]
    unsafe {
        axhal::arch::write_page_table_root0(new_root);
    }
    #[cfg(not(target_arch = "loongarch64"))]
    unsafe {
        axhal::arch::write_page_table_root(new_root);
    }
    *aspace = new_aspace;
    axhal::arch::flush_tlb(None);
    drop(aspace);

    let name = path
        .rsplit_once('/')
        .map_or(path.as_str(), |(_, name)| name);
    let exec_path = path.clone();
    curr.set_name(name);
    *ext.process_data().exe_path.write() = exec_path;

    // 中文注释：`execve()` 成功后要关闭所有带 `FD_CLOEXEC` 的 fd。
    // 否则像 pipe 这类仅靠“对端全部关闭”才能结束的场景，会把旧程序持有的端点泄漏到新程序里。
    let cloexec_fds = FD_CLOEXEC_TABLE
        .read()
        .iter()
        .copied()
        .collect::<Vec<_>>();
    for fd in cloexec_fds {
        close_file_like(fd)?;
    }

    #[cfg(target_arch = "loongarch64")]
    {
        // 中文注释：LoongArch 的 `execve()` 不能继续复用旧 TrapFrame 里的用户寄存器。
        // 否则新程序会带着上一次 syscall 的参数寄存器和旧线程状态进入 `_start`，
        // 在 musl/busybox 的早期启动阶段就可能把局部变量和算术状态读坏。
        let clean_tf = *axhal::arch::UspaceContext::new(entry_point.as_usize(), user_stack_base, 0);
        *tf = clean_tf;
    }
    #[cfg(not(target_arch = "loongarch64"))]
    {
        tf.set_ip(entry_point.as_usize());
        tf.set_sp(user_stack_base.as_usize());
    }
    Ok(0)
}

