fn validate_positive_pid(pid: i32) -> LinuxResult<Pid> {
    if pid <= 0 {
        // 中文注释：`tkill()`/`tgkill()` 的 tid/tgid 参数必须是正数。
        // 用户传入 `-1` 时，不能先转成 `u32` 再去查表，否则会把 `EINVAL` 误报成 `ESRCH`。
        return Err(LinuxError::EINVAL);
    }
    Ok(pid as Pid)
}

fn check_sigset_size(size: usize) -> LinuxResult<()> {
    if size != size_of::<SignalSet>() {
        return Err(LinuxError::EINVAL);
    }
    Ok(())
}

fn parse_signo(signo: u32) -> LinuxResult<Signo> {
    Signo::from_repr(signo as u8).ok_or(LinuxError::EINVAL)
}

fn sanitize_sigaction_flags(act: &mut kernel_sigaction) {
    const SA_RESTORER_COMPAT: u64 = 0x0400_0000;
    let allowed = SA_SIGINFO as u64
        | SA_ONSTACK as u64
        | SA_RESTART as u64
        | SA_NODEFER as u64
        | SA_RESETHAND as u64
        | SA_RESTORER_COMPAT;
    // 中文注释：用户态常会顺手带上一些当前内核暂未使用的附加 flag。
    // 这里先按 Linux 的宽松行为屏蔽未知位，避免像 `madvise11` 这样
    // 仅注册 `SIGBUS` 处理函数的场景被误判成 `EINVAL`。
    act.sa_flags &= allowed;
}

pub fn sys_rt_sigprocmask(
    how: i32,
    set: UserConstPtr<SignalSet>,
    oldset: UserPtr<SignalSet>,
    sigsetsize: usize,
) -> LinuxResult<isize> {
    check_sigset_size(sigsetsize)?;

    StarryTaskExt::of(&current())
        .thread_data()
        .signal
        .with_blocked_mut::<LinuxResult<_>>(|blocked| {
            if let Some(oldset) = nullable!(oldset.get_as_mut())? {
                *oldset = *blocked;
            }

            if let Some(set) = nullable!(set.get_as_ref())? {
                match how as u32 {
                    SIG_BLOCK => *blocked |= *set,
                    SIG_UNBLOCK => *blocked &= !*set,
                    SIG_SETMASK => *blocked = *set,
                    _ => return Err(LinuxError::EINVAL),
                }
            }
            Ok(())
        })?;

    Ok(0)
}

pub fn sys_rt_sigaction(
    signo: u32,
    act: UserConstPtr<kernel_sigaction>,
    oldact: UserPtr<kernel_sigaction>,
    sigsetsize: usize,
) -> LinuxResult<isize> {
    check_sigset_size(sigsetsize)?;

    let signo = parse_signo(signo)?;
    if matches!(signo, Signo::SIGKILL | Signo::SIGSTOP) {
        return Err(LinuxError::EINVAL);
    }

    let curr = current();
    let mut actions = StarryTaskExt::of(&curr)
        .process_data()
        .signal
        .actions
        .lock();
    if let Some(oldact) = nullable!(oldact.get_as_mut())? {
        actions[signo].to_ctype(oldact);
    }
    if let Some(act) = nullable!(act.get_as_ref())? {
        let mut act = *act;
        sanitize_sigaction_flags(&mut act);
        actions[signo] = act.try_into()?;
    }
    Ok(0)
}

pub fn sys_rt_sigpending(set: UserPtr<SignalSet>, sigsetsize: usize) -> LinuxResult<isize> {
    check_sigset_size(sigsetsize)?;
    *set.get_as_mut()? = StarryTaskExt::of(&current()).thread_data().signal.pending();
    Ok(0)
}

fn make_siginfo(signo: u32, code: i32) -> LinuxResult<Option<SignalInfo>> {
    if signo == 0 {
        return Ok(None);
    }
    let signo = parse_signo(signo)?;
    let mut sig = SignalInfo::new(signo, code);
    if matches!(code, x if x == SI_USER as i32 || x == SI_TKILL) {
        let curr = current();
        let ext = StarryTaskExt::of(&curr);
        sig.set_sender_pid(ext.thread.process().pid());
        sig.set_sender_uid(ext.process_data().euid.load(Ordering::SeqCst));
    }
    Ok(Some(sig))
}

pub fn sys_kill(pid: i32, signo: u32) -> LinuxResult<isize> {
    let Some(sig) = make_siginfo(signo, SI_USER as _)? else {
        // TODO: should also check permissions
        return Ok(0);
    };

    match pid {
        1.. => {
            let proc = get_process(pid as Pid)?;
            send_signal_process(&proc, sig)?;
        }
        0 => {
            let pg = StarryTaskExt::of(&current()).thread.process().group();
            send_signal_process_group(&pg, sig)?;
        }
        -1 => {
            for proc in processes() {
                if proc.is_init() {
                    // init process
                    continue;
                }
                send_signal_process(&proc, sig.clone())?;
            }
        }
        ..-1 => {
            let pg = get_process_group((-pid) as Pid)?;
            send_signal_process_group(&pg, sig)?;
        }
    }
    Ok(0)
}

pub fn sys_tkill(tid: i32, signo: u32) -> LinuxResult<isize> {
    let Some(sig) = make_siginfo(signo, SI_TKILL)? else {
        // TODO: should also check permissions
        return Ok(0);
    };

    let tid = validate_positive_pid(tid)?;
    let thr = get_thread(tid)?;
    send_signal_thread(&thr, sig)?;
    Ok(0)
}

pub fn sys_tgkill(tgid: i32, tid: i32, signo: u32) -> LinuxResult<isize> {
    let Some(sig) = make_siginfo(signo, SI_TKILL)? else {
        // TODO: should also check permissions
        return Ok(0);
    };

    let tgid = validate_positive_pid(tgid)?;
    let tid = validate_positive_pid(tid)?;
    send_signal_thread(find_thread_in_group(tgid, tid)?.as_ref(), sig)?;
    Ok(0)
}

fn find_thread_in_group(tgid: Pid, tid: Pid) -> LinuxResult<Arc<Thread>> {
    let thr = get_thread(tid)?;
    if thr.process().pid() != tgid {
        return Err(LinuxError::ESRCH);
    }
    Ok(thr)
}

fn make_queue_signal_info(
    tgid: Pid,
    signo: u32,
    sig: UserConstPtr<SignalInfo>,
) -> LinuxResult<SignalInfo> {
    let signo = parse_signo(signo)?;
    let mut sig = sig.get_as_ref()?.clone();
    sig.set_signo(signo);
    if StarryTaskExt::of(&current()).thread.process().pid() != tgid
        && (sig.code() >= 0 || sig.code() == SI_TKILL)
    {
        return Err(LinuxError::EPERM);
    }
    Ok(sig)
}

pub fn sys_rt_sigqueueinfo(
    tgid: Pid,
    signo: u32,
    sig: UserConstPtr<SignalInfo>,
    sigsetsize: usize,
) -> LinuxResult<isize> {
    check_sigset_size(sigsetsize)?;

    let sig = make_queue_signal_info(tgid, signo, sig)?;
    send_signal_process(get_process(tgid)?.as_ref(), sig)?;
    Ok(0)
}

pub fn sys_rt_tgsigqueueinfo(
    tgid: Pid,
    tid: Pid,
    signo: u32,
    sig: UserConstPtr<SignalInfo>,
    sigsetsize: usize,
) -> LinuxResult<isize> {
    check_sigset_size(sigsetsize)?;

    let sig = make_queue_signal_info(tgid, signo, sig)?;
    send_signal_thread(find_thread_in_group(tgid, tid)?.as_ref(), sig)?;
    Ok(0)
}

pub fn sys_rt_sigreturn(tf: &mut TrapFrame) -> LinuxResult<isize> {
    let curr = current();
    let ext = StarryTaskExt::of(&curr);
    let returning_signo = Signo::from_repr(
        ext.thread_data()
            .current_handler_signo
            .swap(0, Ordering::SeqCst) as u8,
    );
    access_user_memory(|| {
        ext.thread_data().signal.restore(tf);
    });
    let pending_after = ext.thread_data().signal.pending();

    // 中文注释：只在“刚返回的这个 handler 对应信号”仍然 pending 时，
    // 跳过下一次立即检查，避免周期性信号在 `sigreturn()` 后立刻重入，
    // 导致 `setitimer01` 这样的场景卡在 handler 风暴里。
    // 如果 pending 的是别的信号，则不跳过，让 `sigpending02` 这类
    // “不同信号应连续递送”的语义继续成立。
    BLOCK_NEXT_SIGNAL_CHECK.store(
        returning_signo.is_some_and(|signo| pending_after.has(signo)),
        Ordering::SeqCst,
    );
    Ok(tf.retval() as isize)
}

