const O_EXEC: u32 = O_PATH;

fn check_open_mode_bits(mode: NodePermission, file_uid: u32, file_gid: u32, uid: u32, gid: u32, flags: u32) -> LinuxResult<()> {
    if uid == 0 || flags & O_PATH != 0 {
        return Ok(());
    }

    let (need_read, need_write) = match flags & 0b11 {
        O_RDONLY => (true, false),
        O_WRONLY => (false, true),
        _ => (true, true),
    };

    let curr = current();
    let proc_data = StarryTaskExt::of(&curr).process_data();
    let gid_matched = gid == file_gid
        || proc_data
            .supplementary_gids
            .read()
            .iter()
            .any(|supp_gid| *supp_gid == file_gid);

    let (read_bit, write_bit) = if uid == file_uid {
        (NodePermission::OWNER_READ, NodePermission::OWNER_WRITE)
    } else if gid_matched {
        (NodePermission::GROUP_READ, NodePermission::GROUP_WRITE)
    } else {
        (NodePermission::OTHER_READ, NodePermission::OTHER_WRITE)
    };

    if need_read && !mode.contains(read_bit) {
        return Err(LinuxError::EACCES);
    }
    if need_write && !mode.contains(write_bit) {
        return Err(LinuxError::EACCES);
    }
    Ok(())
}

fn inherited_gid(parent_mode: NodePermission, parent_gid: u32, egid: u32) -> u32 {
    if parent_mode.contains(NodePermission::SET_GID) {
        parent_gid
    } else {
        egid
    }
}

/// Convert open flags to [`OpenOptions`].
fn flags_to_options(flags: c_int, mode: __kernel_mode_t, (uid, gid): (u32, u32)) -> OpenOptions {
    let flags = flags as u32;
    let mut options = OpenOptions::new();
    options.mode(mode).user(uid, gid);
    match flags & 0b11 {
        O_RDONLY => options.read(true),
        O_WRONLY => options.write(true),
        _ => options.read(true).write(true),
    };
    if flags & O_APPEND != 0 {
        options.append(true);
    }
    if flags & O_TRUNC != 0 {
        options.truncate(true);
    }
    if flags & O_CREAT != 0 {
        options.create(true);
    }
    if flags & O_EXEC != 0 {
        options.execute(true);
    }
    if flags & O_EXCL != 0 {
        options.create_new(true);
    }
    if flags & O_DIRECTORY != 0 {
        options.directory(true);
    }
    if flags & O_NOFOLLOW != 0 {
        options.no_follow(true);
    }
    options
}

fn add_to_fd(result: OpenResult<RawMutex>, flags: i32) -> LinuxResult<i32> {
    let path_only = flags as u32 & O_PATH != 0;
    match result {
        OpenResult::File(file) => File::new(file, path_only).add_to_fd_table(),
        OpenResult::Dir(dir) => Directory::new(dir).add_to_fd_table(),
    }
}

/// Open or create a file.
/// fd: file descriptor
/// filename: file path to be opened or created
/// flags: open flags
/// mode: see man 7 inode
/// return new file descriptor if succeed, or return -1.
pub fn sys_openat(
    dirfd: c_int,
    path: UserConstPtr<c_char>,
    flags: i32,
    mode: __kernel_mode_t,
) -> LinuxResult<isize> {
    let path = path.get_as_str()?;
    debug!(
        "sys_openat <= {} {:?} {:#o} {:#o}",
        dirfd, path, flags, mode
    );

    let mode = mode & !current_umask();
    let flags_u32 = flags as u32;
    let euid = sys_geteuid()? as u32;
    let egid = sys_getegid()? as u32;

    let options = flags_to_options(flags, mode, (euid, egid));
    with_fs(dirfd, |fs| {
        let mut created_owner = None;

        let resolved = if flags_u32 & O_NOFOLLOW != 0 {
            fs.resolve_no_follow(path)
        } else {
            fs.resolve(path)
        };

        match resolved {
            Ok(loc) => {
                if flags_u32 & O_NOFOLLOW != 0 && loc.node_type() == NodeType::Symlink {
                    return Err(LinuxError::ELOOP);
                }

                let meta = loc.metadata()?;
                if flags_u32 & O_NOATIME != 0 && euid != 0 && meta.uid != euid {
                    return Err(LinuxError::EPERM);
                }

                if loc.is_dir()
                    && flags_u32 & O_PATH == 0
                    && (flags_u32 & 0b11 != O_RDONLY || flags_u32 & O_CREAT != 0)
                {
                    return Err(LinuxError::EISDIR);
                }

                // 中文注释：当前先补最小 FIFO 打开语义。
                // `open06` 只覆盖“写端 O_NONBLOCK 打开且没有读端”这一分支，
                // 这里在没有全局 FIFO 读端跟踪前，先按无读端处理返回 `ENXIO`。
                if meta.node_type == NodeType::Fifo && flags_u32 & O_NONBLOCK != 0 && flags_u32 & 0b11 == O_WRONLY {
                    return Err(LinuxError::ENXIO);
                }

                check_open_mode_bits(meta.mode, meta.uid, meta.gid, euid, egid, flags_u32)?;
            }
            Err(LinuxError::ENOENT) if flags_u32 & O_CREAT != 0 => {
                let (parent, _) = fs.resolve_parent(Path::new(path))?;
                let parent_meta = parent.metadata()?;
                created_owner = Some((euid, inherited_gid(parent_meta.mode, parent_meta.gid, egid)));
            }
            Err(err) => return Err(err),
        }

        let result = options.open(fs, path)?;
        if let (Some(owner), OpenResult::File(file)) = (created_owner, &result) {
            // 中文注释：普通文件新建后也要像 Linux 一样继承父目录的 SGID 组，
            // 否则 `open10` 这类用例会看到新文件仍错误地落在进程自身 gid 上。
            file.inner().update_metadata(MetadataUpdate {
                owner: Some(owner),
                mode: Some(NodePermission::from_bits_truncate(mode as _)),
                ..Default::default()
            })?;
        }
        Ok(result)
    })
        .and_then(|result| add_to_fd(result, flags))
        .map(|fd| fd as isize)
}

/// Open a file by `filename` and insert it into the file descriptor table.
///
/// Return its index in the file table (`fd`). Return `EMFILE` if it already
/// has the maximum number of files open.
pub fn sys_open(
    path: UserConstPtr<c_char>,
    flags: i32,
    mode: __kernel_mode_t,
) -> LinuxResult<isize> {
    sys_openat(AT_FDCWD as _, path, flags, mode)
}

