    Ok(f)
}

fn resize_file(file: &axfs_ng_vfs::FileNode<axsync::RawMutex>, len: u64) -> LinuxResult<()> {
    let cur = file.len()?;
    if len <= cur {
        return Ok(file.set_len(len)?);
    }

    // 中文注释：当前 ext4 后端只实现了截短，未实现“直接把文件扩到更大长度”。
    // 这里改成从 EOF 连续 append 零块扩容，避免 `write_at(offset > EOF)`
    // 内部再次走到未实现的 `set_len(offset)` 分支。
    let mut remain = len - cur;
    let zeros = [0u8; 4096];
    while remain > 0 {
        let chunk = remain.min(zeros.len() as u64) as usize;
        file.append(&zeros[..chunk])?;
        remain -= chunk as u64;
    }
    Ok(())
}

fn write_file_with_offset(file: &File, offset: u64, buf: &[u8], update_pos: bool) -> LinuxResult<usize> {
    let end = offset
        .checked_add(buf.len() as u64)
        .ok_or(LinuxError::EINVAL)?;
    let mut inner = file.inner();

    // 中文注释：先把文件长度补到目标末尾，再做覆盖写入。
    // 这样 `splice(pipe -> file)` 就不会在真实写数据时顺手触发 ext4 的扩容路径，
    // 尽量避开 loongarch64 上目前容易把 extent 元数据写坏的分支。
    if end > inner.access(FileFlags::WRITE)?.len()? {
        inner.access(FileFlags::WRITE)?.set_len(end)?;
    }

    let written = inner.write_at(buf, offset)?;
    if update_pos {
        inner.seek(SeekFrom::Start(offset + written as u64))?;
    }
    Ok(written)
}

/// Read data from the file indicated by `fd`.
///
/// Return the read size if success.
pub fn sys_read(fd: i32, buf: UserPtr<u8>, len: usize) -> LinuxResult<isize> {
    debug!("sys_read <= fd: {}, buf: {:?}, len: {}", fd, buf.address(), len);
    if len == 0 {
        return Ok(0);
    }

    // 中文注释：loongarch64/aarch64 这类架构下，内核不能把用户虚拟地址
    // 直接当成普通 `&mut [u8]` 去写；先读到内核临时缓冲，再统一回写用户态。
    let mut kernel_buf = vec![0; len];
    let read = get_read_file_like(fd)?.read(&mut kernel_buf)?;
    write_user_buf(buf, &kernel_buf[..read])?;
    Ok(read as _)
}

fn readv_impl(
    iov: UserPtr<iovec>,
    iovcnt: usize,
    mut f: impl FnMut(&mut [u8]) -> LinuxResult<usize>,
) -> LinuxResult<isize> {
    if iovcnt == 0 {
        return Ok(0);
    } else if iovcnt > 1024 {
        return Err(LinuxError::EINVAL);
    }

    let iovs = iov.get_as_mut_slice(iovcnt)?;
    let mut total_len = 0u64;
    for iov in iovs.iter() {
        // 中文注释：`readv()` 需要先拒绝 `iov_len` 为负数重解释后的超大值，
        // 否则像 `(size_t)-1` 会被错误地当成“空段”并返回成功。
        if iov.iov_len > isize::MAX as u64 {
            return Err(LinuxError::EINVAL);
        }
        total_len = total_len
            .checked_add(iov.iov_len)
            .ok_or(LinuxError::EINVAL)?;
        if total_len > isize::MAX as u64 {
            return Err(LinuxError::EINVAL);
        }
    }

    let mut ret = 0;
    for iov in iovs {
        if iov.iov_len == 0 {
            continue;
        }
        let user_buf = UserPtr::<u8>::from(iov.iov_base as usize);
        let mut kernel_buf = vec![0; iov.iov_len as usize];
        let read = f(&mut kernel_buf)?;
        write_user_buf(user_buf, &kernel_buf[..read])?;
        ret += read;

        if read < kernel_buf.len() {
            break;
        }
    }

    Ok(ret as isize)
}

fn writev_impl(
    iov: UserConstPtr<iovec>,
    iovcnt: usize,
    mut f: impl FnMut(&[u8]) -> LinuxResult<usize>,
) -> LinuxResult<isize> {
    if iovcnt == 0 {
        return Ok(0);
    } else if iovcnt > 1024 {
        return Err(LinuxError::EINVAL);
    }

    let iovs = iov.get_as_slice(iovcnt)?;

    let bufs = iovs
        .iter()
        .filter_map(|iov| {
            if iov.iov_len == 0 {
                None
            } else {
                let buf = UserConstPtr::<u8>::from(iov.iov_base as usize);
                Some(buf.get_as_slice(iov.iov_len as _))
            }
        })
        .collect::<LinuxResult<Vec<_>>>()?;

    let mut ret = 0;
    for buf in bufs {
        let write = f(buf)?;
        ret += write;

        if write < buf.len() {
            break;
        }
    }

    Ok(ret as isize)
}

pub fn sys_readv(fd: i32, iov: UserPtr<iovec>, iovcnt: usize) -> LinuxResult<isize> {
    debug!("sys_readv <= fd: {}, iovcnt: {}", fd, iovcnt);
    let f = get_read_file_like(fd)?;
    readv_impl(iov, iovcnt, |buf| f.read(buf))
}

/// Write data to the file indicated by `fd`.
///
/// Return the written size if success.
pub fn sys_write(fd: i32, buf: UserConstPtr<u8>, len: usize) -> LinuxResult<isize> {
    if len == 0 {
        // 中文注释：Linux 允许 `write(fd, NULL, 0)` 直接成功返回 0，
        // 不能因为空指针去提前做用户内存访问检查。
        return Ok(0);
    }
    let buf = buf.get_as_slice(len)?;
    debug!(
        "sys_write <= fd: {}, buf: {:p}, len: {}",
        fd,
        buf.as_ptr(),
        buf.len()
    );
    use linux_raw_sys::general::{RLIMIT_FSIZE, RLIM_INFINITY, SI_KERNEL};
    use starry_core::task::{current, StarryTaskExt};
    let curr = current();
    let fsize_limit = StarryTaskExt::of(&curr)
        .process_data()
        .rlim
        .read()[RLIMIT_FSIZE]
        .current;

    if fsize_limit != RLIM_INFINITY as u64 {
        if let Ok(file) = crate::file::File::from_fd(fd) {
            // 中文注释：这里必须读取 fd 当前记录的真实偏移，
            // 不能用 seek(Current(0))，否则超过 EOF 的合法偏移会被错误裁回文件大小。
            let current_pos = file.inner().position();
            if current_pos + buf.len() as u64 > fsize_limit {
                use axsignal::{SignalInfo, Signo};
                let proc = StarryTaskExt::of(&curr).process_data();
                let sig_info = SignalInfo::new(Signo::SIGXFSZ, SI_KERNEL as i32);
                proc.signal.send_signal(sig_info);
                return Err(LinuxError::EFBIG);
            }
        }
    }

    Ok(get_file_like(fd)?.write(buf)? as _)
}

pub fn sys_writev(fd: i32, iov: UserConstPtr<iovec>, iovcnt: usize) -> LinuxResult<isize> {
    debug!("sys_writev <= fd: {}, iovcnt: {}", fd, iovcnt);
    use linux_raw_sys::general::{RLIMIT_FSIZE, RLIM_INFINITY, SI_KERNEL};
    use starry_core::task::{current, StarryTaskExt};
    let curr = current();
    let fsize_limit = StarryTaskExt::of(&curr)
        .process_data()
        .rlim
        .read()[RLIMIT_FSIZE]
        .current;

    if fsize_limit != RLIM_INFINITY as u64 {
        if let Ok(file) = crate::file::File::from_fd(fd) {
            let total_len = if iovcnt == 0 {
                0usize
            } else if iovcnt > 1024 {
                return Err(LinuxError::EINVAL);
            } else {
                let iovs = iov.get_as_slice(iovcnt)?;
                iovs.iter().map(|iov| iov.iov_len as usize).sum::<usize>()
            };
            // 中文注释：writev 也要基于当前 fd 的真实偏移做限制检查，
            // 否则 lseek 到 EOF 之后的位置会被误判成仍在文件尾。
            let current_pos = file.inner().position();
            if current_pos + total_len as u64 > fsize_limit {
                use axsignal::{SignalInfo, Signo};
                let proc = StarryTaskExt::of(&curr).process_data();
                let sig_info = SignalInfo::new(Signo::SIGXFSZ, SI_KERNEL as i32);
                proc.signal.send_signal(sig_info);
                return Err(LinuxError::EFBIG);
            }
        }
    }

    let f = get_file_like(fd)?;
    writev_impl(iov, iovcnt, |buf| f.write(buf))
}

