pub fn sys_socket(domain: u32, raw_ty: u32, proto: u32) -> LinuxResult<isize> {
    debug!(
        "sys_socket <= domain: {}, ty: {}, proto: {}",
        domain, raw_ty, proto
    );
    let ty = raw_ty & 0xFF;

    match domain {
        AF_INET | AF_INET6 => {
            let socket = match ty {
                SOCK_STREAM => {
                    if proto != 0 && proto != IPPROTO_TCP as _ {
                        return Err(LinuxError::EPROTONOSUPPORT);
                    }
                    Socket::Tcp(Mutex::new(TcpSocket::new()))
                }
                SOCK_DGRAM => {
                    if proto != 0 && proto != IPPROTO_UDP as _ {
                        return Err(LinuxError::EPROTONOSUPPORT);
                    }
                    Socket::Udp(Mutex::new(UdpSocket::new()))
                }
                SOCK_RAW => return Err(LinuxError::EPROTONOSUPPORT),
                _ => return Err(LinuxError::EINVAL),
            };
            if raw_ty & O_NONBLOCK != 0 {
                socket.set_nonblocking(true)?;
            }
            let fd = socket.add_to_fd_table()?;
            if raw_ty & O_CLOEXEC != 0 {
                // 中文注释：`SOCK_CLOEXEC` 需要把新创建的 socket fd 标记为 close-on-exec。
                set_fd_cloexec(fd, true)?;
            }
            Ok(fd as isize)
        }
        AF_UNIX => {
            // Unix domain socket
            let socket = match ty {
                SOCK_STREAM | SOCK_DGRAM => UnixSocket::new(ty),
                SOCK_RAW => return Err(LinuxError::EPROTONOSUPPORT),
                _ => return Err(LinuxError::EINVAL),
            };
            if raw_ty & O_NONBLOCK != 0 {
                // TODO: set nonblocking for UnixSocket
            }
            let fd = socket.add_to_fd_table()?;
            if raw_ty & O_CLOEXEC != 0 {
                set_fd_cloexec(fd, true)?;
            }
            Ok(fd as isize)
        }
        _ => Err(LinuxError::EAFNOSUPPORT),
    }
}

pub fn sys_socketpair(
    domain: u32,
    raw_ty: u32,
    proto: u32,
    sv: UserPtr<[i32; 2]>,
) -> LinuxResult<isize> {
    debug!(
        "sys_socketpair <= domain: {}, ty: {}, proto: {}",
        domain, raw_ty, proto
    );
    let ty = raw_ty & 0xFF;

    if domain != AF_UNIX {
        return Err(LinuxError::EAFNOSUPPORT);
    }
    if proto != 0 {
        return Err(LinuxError::EPROTONOSUPPORT);
    }
    if ty != SOCK_STREAM {
        return Err(LinuxError::EOPNOTSUPP);
    }

    let (left, right) = UnixSocket::new_pair(ty);
    let left = alloc::sync::Arc::new(left);
    let right = alloc::sync::Arc::new(right);
    *left.peer_socket.lock() = Some(right.clone());
    *right.peer_socket.lock() = Some(left.clone());
    *left.peer_addr.lock() = Some(UnixAddr::Abstract(alloc::vec![]));
    *right.peer_addr.lock() = Some(UnixAddr::Abstract(alloc::vec![]));

    let fd0 = crate::file::add_file_like(left)?;
    let fd1 = crate::file::add_file_like(right)?;
    if raw_ty & O_CLOEXEC != 0 {
        // 中文注释：`socketpair(..., SOCK_CLOEXEC, ...)` 两端都要继承 cloexec 标志。
        set_fd_cloexec(fd0, true)?;
        set_fd_cloexec(fd1, true)?;
    }
    let sv = sv.get_as_mut()?;
    sv[0] = fd0;
    sv[1] = fd1;
    Ok(0)
}

pub fn sys_bind(fd: i32, addr: UserConstPtr<sockaddr>, addrlen: u32) -> LinuxResult<isize> {
    let family = sockaddr_family(addr, addrlen)?;

    match family {
        AF_UNIX => {
            let unix_addr = UnixAddr::read_from_user(addr, addrlen)?;
            debug!("sys_bind <= fd: {}, unix_addr: {:?}", fd, unix_addr);

            // Try to get UnixSocket first, fall back to error handling for other socket types
            let socket = UnixSocket::from_fd(fd);
            if let Ok(unix_sock) = socket {
                unix_sock.bind(unix_addr)?;
                return Ok(0);
            }

