            let sock = Socket::from_fd(fd);
            if let Ok(_) = sock {
                // Regular socket trying to bind to Unix address - wrong address family
                return Err(LinuxError::EAFNOSUPPORT);
            }

            // File descriptor exists but not a socket
            Err(LinuxError::ENOTSOCK)
        }
        AF_INET | AF_INET6 => {
            let addr = SocketAddr::read_from_user(addr, addrlen)?;
            debug!("sys_bind <= fd: {}, addr: {:?}", fd, addr);

            if !is_local_bind_addr(&addr) {
                return Err(LinuxError::EADDRNOTAVAIL);
            }

            Socket::from_fd(fd)?.bind(addr)?;

            Ok(0)
        }
        _ => Err(LinuxError::EAFNOSUPPORT),
    }
}

