        Arc::new(RwLock::new(BTreeSet::new()));
}

/// Get a file-like object by `fd`.
pub fn get_file_like(fd: c_int) -> LinuxResult<Arc<dyn FileLike>> {
    FD_TABLE
        .read()
        .get(fd as usize)
        .cloned()
        .ok_or(LinuxError::EBADF)
}

/// Add a file to the file descriptor table.
pub fn add_file_like(f: Arc<dyn FileLike>) -> LinuxResult<c_int> {
    let max_nofile =
        StarryTaskExt::of(&current()).process_data().rlim.read()[RLIMIT_NOFILE].current;
    let mut table = FD_TABLE.write();
    if table.count() as u64 >= max_nofile {
        return Err(LinuxError::EMFILE);
    }
    Ok(table.add(f).map_err(|_| LinuxError::EMFILE)? as c_int)
}

/// Add a file to the file descriptor table with minimum fd constraint.
///
/// Returns the smallest available fd >= min_fd.
pub fn add_file_like_from(f: Arc<dyn FileLike>, min_fd: c_int) -> LinuxResult<c_int> {
    let max_nofile =
        StarryTaskExt::of(&current()).process_data().rlim.read()[RLIMIT_NOFILE].current;
    let mut table = FD_TABLE.write();
    if table.count() as u64 >= max_nofile {
        return Err(LinuxError::EMFILE);
    }

    // Find the smallest available fd >= min_fd
    for fd in min_fd as usize..max_nofile as usize {
        if !table.is_assigned(fd) {
            table.add_at(fd, f).map_err(|_| LinuxError::EMFILE)?;
            return Ok(fd as c_int);
        }
    }

    Err(LinuxError::EMFILE)
}

/// Close a file by `fd`.
pub fn close_file_like(fd: c_int) -> LinuxResult {
    let f = FD_TABLE
        .write()
        .remove(fd as usize)
        .ok_or(LinuxError::EBADF)?;
    debug!("close_file_like <= count: {}", Arc::strong_count(&f));

    // Remove FD_CLOEXEC flag if present
    FD_CLOEXEC_TABLE.write().remove(&fd);

    // Call close to cleanup resources (e.g., Unix socket namespace)
    f.close()?;

    Ok(())
}

/// Set FD_CLOEXEC flag for a fd.
pub fn set_fd_cloexec(fd: c_int, cloexec: bool) -> LinuxResult {
    if !FD_TABLE.read().is_assigned(fd as usize) {
        return Err(LinuxError::EBADF);
    }

    let mut table = FD_CLOEXEC_TABLE.write();
    if cloexec {
        table.insert(fd);
    } else {
        table.remove(&fd);
    }
    Ok(())
}

/// Get FD_CLOEXEC flag for a fd.
pub fn get_fd_cloexec(fd: c_int) -> LinuxResult<bool> {
    if !FD_TABLE.read().is_assigned(fd as usize) {
        return Err(LinuxError::EBADF);
    }

    Ok(FD_CLOEXEC_TABLE.read().contains(&fd))
}

