static SPECIAL_RDEV_TABLE: RwLock<BTreeMap<(u64, u64), DeviceId>> = RwLock::new(BTreeMap::new());

pub fn register_special_file_rdev(metadata: &Metadata, rdev: DeviceId) {
    SPECIAL_RDEV_TABLE
        .write()
        .insert((metadata.device, metadata.inode), rdev);
}

fn lookup_special_file_rdev(metadata: &Metadata) -> Option<DeviceId> {
    SPECIAL_RDEV_TABLE
        .read()
        .get(&(metadata.device, metadata.inode))
        .copied()
}

pub fn with_fs<R>(
    dirfd: c_int,
    f: impl FnOnce(&mut FsContext<RawMutex>) -> LinuxResult<R>,
) -> LinuxResult<R> {
    let mut fs = FS_CONTEXT.lock();
    if dirfd == AT_FDCWD {
        f(&mut fs)
    } else {
        let dir = Directory::from_fd(dirfd)?.inner.clone();
        f(&mut fs.with_current_dir(dir)?)
    }
}

pub enum ResolveAtResult {
    File(Location<RawMutex>),
    Other(Arc<dyn FileLike>),
}
impl ResolveAtResult {
    pub fn into_file(self) -> Option<Location<RawMutex>> {
        match self {
            Self::File(file) => Some(file),
            Self::Other(_) => None,
        }
    }

    pub fn stat(&self) -> LinuxResult<Kstat> {
        match self {
            Self::File(file) => file.metadata().map(|it| metadata_to_kstat(&it)),
            Self::Other(file_like) => file_like.stat(),
        }
    }
}

pub fn resolve_at(dirfd: c_int, path: Option<&str>, flags: u32) -> LinuxResult<ResolveAtResult> {
    match path {
        Some("") | None => {
            if flags & AT_EMPTY_PATH == 0 {
                return Err(LinuxError::ENOENT);
            }
            let file_like = get_file_like(dirfd)?;
            let f = file_like.clone().into_any();
            Ok(if let Some(file) = f.downcast_ref::<File>() {
                ResolveAtResult::File(file.inner().inner().clone())
            } else if let Some(dir) = f.downcast_ref::<Directory>() {
                ResolveAtResult::File(dir.inner().clone())
            } else {
                ResolveAtResult::Other(file_like)
            })
        }
        Some(path) => {
            // Check for pathname too long before resolving dirfd
            const PATH_MAX: usize = 4096;
            if path.len() > PATH_MAX {
                return Err(LinuxError::ENAMETOOLONG);
            }
            // Absolute paths should ignore dirfd
            if path.starts_with('/') {
                let fs = FS_CONTEXT.lock();
                if flags & AT_SYMLINK_NOFOLLOW != 0 {
                    fs.resolve_no_follow(path)
                } else {
                    fs.resolve(path)
                }
                .map(ResolveAtResult::File)
            } else {
                with_fs(dirfd, |fs| {
                    if flags & AT_SYMLINK_NOFOLLOW != 0 {
                        fs.resolve_no_follow(path)
                    } else {
                        fs.resolve(path)
                    }
                    .map(ResolveAtResult::File)
                })
            }
        }
    }
}

pub fn metadata_to_kstat(metadata: &Metadata) -> Kstat {
    let ty = metadata.node_type as u8;
    let perm = metadata.mode.bits() as u32;
    let mode = ((ty as u32) << 12) | perm;
    let rdev = if metadata.rdev == DeviceId::default()
        && matches!(
            metadata.node_type,
            NodeType::CharacterDevice | NodeType::BlockDevice
        )
    {
        lookup_special_file_rdev(metadata).unwrap_or_default()
    } else {
        metadata.rdev
    };
    Kstat {
        dev: metadata.device,
        ino: metadata.inode,
        mode,
        nlink: metadata.nlink as _,
        uid: metadata.uid,
        gid: metadata.gid,
        size: metadata.size,
        blksize: metadata.block_size as _,
        blocks: metadata.blocks,
        rdev,
        atime: metadata.atime,
        mtime: metadata.mtime,
        ctime: metadata.ctime,
    }
}

