pub struct EpollInstance {
    events: Mutex<BTreeMap<c_int, epoll_event>>,
}

impl EpollInstance {
    fn new() -> Self {
        Self {
            events: Mutex::new(BTreeMap::new()),
        }
    }

    fn from_fd(fd: c_int) -> LinuxResult<Arc<Self>> {
        FileLike::from_fd(fd)
    }

    fn control(
        &self,
        epfd: c_int,
        op: c_int,
        fd: c_int,
        event: Option<&epoll_event>,
    ) -> LinuxResult<isize> {
        if fd == epfd {
            return Err(LinuxError::EINVAL);
        }

        let target = get_file_like(fd)?;
        if !is_epoll_target_supported(target) {
            return Err(LinuxError::EPERM);
        }

        match op as u32 {
            EPOLL_CTL_ADD => {
                let event = event.ok_or(LinuxError::EFAULT)?;
                if let Entry::Vacant(entry) = self.events.lock().entry(fd) {
                    entry.insert(*event);
                    Ok(0)
                } else {
                    Err(LinuxError::EEXIST)
                }
            }
            EPOLL_CTL_MOD => {
                let event = event.ok_or(LinuxError::EFAULT)?;
                let mut events = self.events.lock();
                if let Entry::Occupied(mut entry) = events.entry(fd) {
                    entry.insert(*event);
                    Ok(0)
                } else {
                    Err(LinuxError::ENOENT)
                }
            }
            EPOLL_CTL_DEL => {
                let mut events = self.events.lock();
                if let Entry::Occupied(entry) = events.entry(fd) {
                    entry.remove_entry();
                    Ok(0)
                } else {
                    Err(LinuxError::ENOENT)
                }
            }
            _ => Err(LinuxError::EINVAL),
        }
    }

    fn poll_all(&self, events: &mut [epoll_event]) -> LinuxResult<usize> {
        let ready_list = self.events.lock();
        let mut events_num = 0usize;

        for (fd, watched) in ready_list.iter() {
            if events_num >= events.len() {
                break;
            }

            let mut ready = 0u32;
            match get_file_like(*fd)?.poll() {
                Ok(PollState { readable, writable }) => {
                    if readable && watched.events & EPOLLIN != 0 {
                        ready |= EPOLLIN;
                    }
                    if writable && watched.events & EPOLLOUT != 0 {
                        ready |= EPOLLOUT;
                    }
                }
                Err(_) if watched.events & EPOLLERR != 0 => {
                    ready |= EPOLLERR;
                }
                Err(_) => {}
            }

            if ready != 0 {
                events[events_num] = epoll_event {
                    events: ready,
                    data: watched.data,
                };
                events_num += 1;
            }
        }

        Ok(events_num)
    }
}

impl FileLike for EpollInstance {
    fn read(&self, _buf: &mut [u8]) -> LinuxResult<usize> {
        Err(LinuxError::EINVAL)
    }

    fn write(&self, _buf: &[u8]) -> LinuxResult<usize> {
        Err(LinuxError::EINVAL)
    }

    fn stat(&self) -> LinuxResult<crate::file::Kstat> {
        Ok(crate::file::Kstat {
            mode: 0o600,
            ..Default::default()
        })
    }

    fn into_any(self: Arc<Self>) -> Arc<dyn core::any::Any + Send + Sync> {
        self
    }

    fn poll(&self) -> LinuxResult<PollState> {
        Err(LinuxError::EINVAL)
    }
}

fn is_epoll_target_supported(file: Arc<dyn FileLike>) -> bool {
    let any = file.into_any();
    any.is::<Pipe>()
        || any.is::<Socket>()
        || any.is::<UnixSocket>()
        || any.is::<Stdin>()
        || any.is::<Stdout>()
}

fn wait_epoll(
    epfd: c_int,
    events: UserPtr<epoll_event>,
    maxevents: c_int,
    timeout: Option<Duration>,
) -> LinuxResult<isize> {
    if maxevents <= 0 {
        return Err(LinuxError::EINVAL);
    }

    let events = events.get_as_mut_slice(maxevents as usize)?;
    let deadline = timeout.map(|it| wall_time() + it);
    let epoll = EpollInstance::from_fd(epfd)?;

    loop {
        axnet::poll_interfaces();

        let res = epoll.poll_all(events)?;
        if res > 0 {
            return Ok(res as _);
        }

        if deadline.is_some_and(|it| wall_time() >= it) {
            return Ok(0);
        }

        axtask::yield_now();
    }
}

pub fn sys_epoll_create1(flags: c_int) -> LinuxResult<isize> {
    debug!("sys_epoll_create1 <= flags: {:#x}", flags);

    if flags & !(EPOLL_CLOEXEC as c_int) != 0 {
        return Err(LinuxError::EINVAL);
    }

    let fd = add_file_like(Arc::new(EpollInstance::new()))?;
    if flags & EPOLL_CLOEXEC as c_int != 0 {
        // 中文注释：`epoll_create1(EPOLL_CLOEXEC)` 需要把 close-on-exec 标志直接挂到新 fd 上。
        set_fd_cloexec(fd, true)?;
    }
    Ok(fd as _)
}

pub fn sys_epoll_ctl(
    epfd: c_int,
    op: c_int,
    fd: c_int,
    event: UserConstPtr<epoll_event>,
) -> LinuxResult<isize> {
    debug!("sys_epoll_ctl <= epfd: {} op: {} fd: {}", epfd, op, fd);

    let event = if op as u32 == EPOLL_CTL_DEL {
        None
    } else {
        Some(event.get_as_ref()?)
    };

    EpollInstance::from_fd(epfd)?.control(epfd, op, fd, event)
}

pub fn sys_epoll_wait(
    epfd: c_int,
    events: UserPtr<epoll_event>,
    maxevents: c_int,
    timeout: c_int,
) -> LinuxResult<isize> {
    debug!(
        "sys_epoll_wait <= epfd: {} maxevents: {} timeout: {}",
        epfd, maxevents, timeout
    );

    wait_epoll(
        epfd,
        events,
        maxevents,
        (!timeout.is_negative()).then(|| Duration::from_millis(timeout as u64)),
    )
}

pub fn sys_epoll_pwait(
    epfd: c_int,
    events: UserPtr<epoll_event>,
    maxevents: c_int,
    timeout: c_int,
    _sigmask: UserConstPtr<SignalSet>,
    _sigsetsize: usize,
) -> LinuxResult<isize> {
    debug!(
        "sys_epoll_pwait <= epfd: {} maxevents: {} timeout: {}",
        epfd, maxevents, timeout
    );
    wait_epoll(
        epfd,
        events,
        maxevents,
        (!timeout.is_negative()).then(|| Duration::from_millis(timeout as u64)),
    )
}

pub fn sys_epoll_pwait2(
    epfd: c_int,
    events: UserPtr<epoll_event>,
    maxevents: c_int,
    timeout: UserConstPtr<__kernel_timespec>,
    _sigmask: UserConstPtr<SignalSet>,
    _sigsetsize: usize,
) -> LinuxResult<isize> {
    debug!(
        "sys_epoll_pwait2 <= epfd: {} maxevents: {} timeout_ptr: {:?}",
        epfd,
        maxevents,
        timeout.address()
    );
    wait_epoll(
        epfd,
        events,
        maxevents,
        nullable!(timeout.get_as_ref())?
            .map(|ts| ts.try_into_time_value())
            .transpose()?,
    )
}

