static SHM_SYSCTL_SHMMAX: RwLock<usize> = RwLock::new(SHM_SYSCTL_SHMMAX_DEFAULT);
static SHM_SYSCTL_SHMMNI: RwLock<usize> = RwLock::new(SHM_SYSCTL_SHMMNI_DEFAULT);
static SHM_SYSCTL_SHMALL: RwLock<usize> = RwLock::new(SHM_SYSCTL_SHMALL_DEFAULT);

/// `/proc/sys/fs/pipe-max-size` 默认值，与 Linux PIPE_DEF_BUFFERS(16) × PAGE_SIZE 一致。
const PIPE_MAX_SIZE_DEFAULT: usize = 65536;
static PIPE_MAX_SIZE: RwLock<usize> = RwLock::new(PIPE_MAX_SIZE_DEFAULT);

/// `/proc/sys/kernel/domainname` 默认值。
static DOMAINNAME: RwLock<Vec<u8>> = RwLock::new(Vec::new());

fn proc_sysvipc_shm_snapshot() -> Vec<u8> {
    let snapshot = SYSVIPC_SHM_SNAPSHOT.read();
    if snapshot.is_empty() {
        SYSVIPC_SHM_HEADER.as_bytes().to_vec()
    } else {
        snapshot.clone()
    }
}

/// Update `/proc/sysvipc/shm` snapshot content.
pub fn update_proc_sysvipc_shm_snapshot(content: Vec<u8>) {
    *SYSVIPC_SHM_SNAPSHOT.write() = if content.is_empty() {
        SYSVIPC_SHM_HEADER.as_bytes().to_vec()
    } else {
        content
    };
}

/// Append one `/proc/sysvipc/shm` record line to the cached snapshot.
pub fn append_proc_sysvipc_shm_snapshot_line(line: &[u8]) {
    let mut snapshot = SYSVIPC_SHM_SNAPSHOT.write();
    if snapshot.is_empty() {
        snapshot.extend_from_slice(SYSVIPC_SHM_HEADER.as_bytes());
    }
    snapshot.extend_from_slice(line);
}

/// Remove one `/proc/sysvipc/shm` record from the cached snapshot by shmid.
pub fn remove_proc_sysvipc_shm_snapshot_shmid(shmid: i32) {
    let mut snapshot = SYSVIPC_SHM_SNAPSHOT.write();
    if snapshot.is_empty() {
        snapshot.extend_from_slice(SYSVIPC_SHM_HEADER.as_bytes());
        return;
    }

    let mut next = Vec::with_capacity(snapshot.len());
    let Ok(text) = str::from_utf8(&snapshot) else {
        next.extend_from_slice(SYSVIPC_SHM_HEADER.as_bytes());
        *snapshot = next;
        return;
    };

    for (idx, line) in text.lines().enumerate() {
        if idx == 0 {
            next.extend_from_slice(line.as_bytes());
            next.push(b'\n');
            continue;
        }

        let remove = line
            .split_whitespace()
            .nth(1)
            .and_then(|value| value.parse::<i32>().ok())
            == Some(shmid);
        if !remove {
            next.extend_from_slice(line.as_bytes());
            next.push(b'\n');
        }
    }
    *snapshot = next;
}

fn read_shm_sysctl(value: &RwLock<usize>) -> Vec<u8> {
    format!("{}\n", *value.read()).into_bytes()
}

fn write_shm_sysctl(value: &RwLock<usize>, data: &[u8]) -> VfsResult<()> {
    let text = str::from_utf8(data)
        .map_err(|_| VfsError::EINVAL)?
        .trim_end();
    if text.is_empty() {
        // 中文注释：很多用户态工具会用 `O_TRUNC`/`fopen("w")` 先把 proc 节点清空再回写，
        // 对 sysctl 伪文件这里应忽略这次空写，不能把“打开写入”直接变成 `EINVAL`。
        return Ok(());
    }
    let parsed = text.parse::<usize>().map_err(|_| VfsError::EINVAL)?;
    *value.write() = parsed;
    Ok(())
}

