}

/// 全局可回收 tmpfs 实例，供 OOM 时自动释放内存。
static RECLAIMABLE_FS: Mutex<Vec<Weak<MemoryFs>>> = Mutex::new(Vec::new());

impl MemoryFs {
    /// Creates a new empty memory filesystem.
    #[allow(clippy::new_ret_no_self)]
    pub fn new() -> Filesystem<RawMutex> {
        let fs = Arc::new(Self {
            inodes: Mutex::new(Slab::new()),
            root: Mutex::default(),
        });
        // 注册到全局回收列表
        RECLAIMABLE_FS.lock().push(Arc::downgrade(&fs));
        let root_ino = Inode::new(
            &fs,
            None,
            NodeType::Directory,
            NodePermission::from_bits_truncate(0o755),
        );
        *fs.root.lock() = Some(DirEntry::new_dir(
            |this| DirNode::new(MemoryNode::new(fs.clone(), root_ino, Some(this))),
            Reference::root(),
        ));
        Filesystem::new(fs)
    }

    fn get(&self, ino: u64) -> Arc<Inode> {
        self.inodes.lock()[ino as usize - 1].clone()
    }

    /// 截断所有普通文件以释放内存。
    /// 在 OOM 压力下调用可快速回收 tmpfs 占用的空间。
    pub fn truncate_all_files(&self) {
        for (_, inode) in self.inodes.lock().iter() {
            if let NodeContent::File(content) = &inode.content {
                content.content.lock().set_len(0);
            }
        }
    }
}

