use core::mem;

use axerrno::{LinuxError, LinuxResult};
use axhal::time::{TimeValue, wall_time};
use axsignal::{SignalSet, Signo};
use axtask::current;
use linux_raw_sys::general::{POLLERR, POLLIN, POLLNVAL, POLLOUT, RLIMIT_NOFILE, pollfd, timespec};
use starry_core::task::StarryTaskExt;

use crate::{
    file::get_file_like,
    ptr::{UserConstPtr, UserPtr, nullable},
    time::TimeValueLike,
};

fn validate_nfds(nfds: i32) -> LinuxResult<usize> {
    if nfds < 0 {
        return Err(LinuxError::EINVAL);
    }

    let nfds = nfds as usize;
    let curr = current();
    let max_nfds =
        StarryTaskExt::of(&curr).process_data().rlim.read()[RLIMIT_NOFILE].current as usize;
    if nfds > max_nfds {
        return Err(LinuxError::EINVAL);
    }
    Ok(nfds)
}

fn has_unblocked_pending_signals() -> bool {
    let curr = current();
    let signal = &StarryTaskExt::of(&curr).thread_data().signal;
    let pending = signal.pending();
    let blocked = signal.blocked();
    !(pending & !blocked).is_empty()
}

fn do_poll(fds: &mut [pollfd], timeout: Option<TimeValue>) -> LinuxResult<isize> {
    debug!("do_poll fds={:?} timeout={:?}", fds, timeout);

    let deadline = timeout.map(|t| wall_time() + t);

    loop {
        axnet::poll_interfaces();

        let mut res = 0usize;
        for fd in &mut *fds {
            let mut revents = 0;
            match get_file_like(fd.fd) {
                Ok(f) => match f.poll() {
                    Ok(state) => {
                        if (fd.events & POLLIN as i16) != 0 && state.readable {
                            revents |= POLLIN;
                        }
                        if (fd.events & POLLOUT as i16) != 0 && state.writable {
                            revents |= POLLOUT;
                        }
                    }
                    Err(e) => {
                        debug!("poll fd={} error: {:?}", fd.fd, e);
                        revents = POLLERR;
                    }
                },
                Err(_) => {
                    revents = POLLNVAL;
                }
            }
            fd.revents = revents as _;
            if revents != 0 {
                res += 1;
            }
        }

        if res > 0 {
            return Ok(res as _);
        }

        if has_unblocked_pending_signals() {
            return Err(LinuxError::EINTR);
        }

        if deadline.is_some_and(|d| wall_time() >= d) {
            return Ok(0);
        }

        axtask::yield_now();
    }
}

pub fn sys_poll(fds: UserPtr<pollfd>, nfds: u32, timeout: i32) -> LinuxResult<isize> {
    let fds = fds.get_as_mut_slice(nfds as usize)?;
    let timeout = if timeout < 0 {
        None
    } else {
        Some(TimeValue::from_millis(timeout as u64))
    };
    do_poll(fds, timeout)
}

pub fn sys_ppoll(
    fds: UserPtr<pollfd>,
    nfds: i32,
    timeout: UserConstPtr<timespec>,
    sigmask: UserConstPtr<SignalSet>,
    sigsetsize: usize,
) -> LinuxResult<isize> {
    let nfds = validate_nfds(nfds)?;
    let fds = fds.get_as_mut_slice(nfds)?;
    let timeout = nullable!(timeout.get_as_ref())?
        .map(|ts| ts.try_into_time_value())
        .transpose()?;
    let sigmask = nullable!(sigmask.get_as_ref())?.copied();

    if sigmask.is_some() && sigsetsize != size_of::<SignalSet>() {
        return Err(LinuxError::EINVAL);
    }

    if let Some(mut sigmask) = sigmask {
        // 中文注释：`ppoll()` 只在本次等待期间临时替换线程 signal mask，
        // 返回时必须恢复原值；同时 `SIGKILL/SIGSTOP` 永远不能被真正屏蔽。
        sigmask.remove(Signo::SIGKILL);
        sigmask.remove(Signo::SIGSTOP);

        let curr = current();
        let signal = &StarryTaskExt::of(&curr).thread_data().signal;
        let old_blocked = signal.with_blocked_mut(|blocked| mem::replace(blocked, sigmask));
        let result = do_poll(fds, timeout);
        signal.with_blocked_mut(|blocked| *blocked = old_blocked);
        result
    } else {
        do_poll(fds, timeout)
    }
}

