fn check_shm_access(shmid_ds: &ShmidDs, requested_mode: __kernel_mode_t) -> LinuxResult<()> {
    if requested_mode == 0 {
        return Ok(());
    }

    let curr = current();
    let proc_data = StarryTaskExt::of(&curr).process_data();
    let euid = proc_data.euid.load(core::sync::atomic::Ordering::Relaxed);
    if euid == 0 {
        return Ok(());
    }

    let egid = proc_data.egid.load(core::sync::atomic::Ordering::Relaxed);
    let supplementary_gids = proc_data.supplementary_gids.read();
    let shm_perm = shmid_ds.shm_perm;
    let granted_bits = if euid == shm_perm.uid || euid == shm_perm.cuid {
        (shm_perm.mode >> 6) & 0o7
    } else if egid == shm_perm.gid
        || egid == shm_perm.cgid
        || supplementary_gids.contains(&shm_perm.gid)
        || supplementary_gids.contains(&shm_perm.cgid)
    {
        (shm_perm.mode >> 3) & 0o7
    } else {
        shm_perm.mode & 0o7
    };
    let requested_bits = (requested_mode >> 6) & 0o7;

    if requested_bits & granted_bits == requested_bits {
        Ok(())
    } else {
        Err(LinuxError::EACCES)
    }
}

