#[derive(Copy, Clone, PartialEq)]
enum RingBufferStatus {
    Full,
    Empty,
    Normal,
}

const RING_BUFFER_SIZE: usize = 65536; // 64 KiB (must be >= PIPE_MAX to prevent pipe-to-pipe splice deadlock)
const PIPE_WAIT_SLICE: Duration = Duration::from_millis(100);

struct PipeRingBuffer {
    arr: [u8; RING_BUFFER_SIZE],
    head: usize,
    tail: usize,
    status: RingBufferStatus,
}

impl PipeRingBuffer {
    const fn new() -> Self {
        Self {
            arr: [0; RING_BUFFER_SIZE],
            head: 0,
            tail: 0,
            status: RingBufferStatus::Empty,
        }
    }

    fn write_byte(&mut self, byte: u8) {
        self.status = RingBufferStatus::Normal;
        self.arr[self.tail] = byte;
        self.tail = (self.tail + 1) % RING_BUFFER_SIZE;
        if self.tail == self.head {
            self.status = RingBufferStatus::Full;
        }
    }

    fn read_byte(&mut self) -> u8 {
        self.status = RingBufferStatus::Normal;
        let c = self.arr[self.head];
        self.head = (self.head + 1) % RING_BUFFER_SIZE;
        if self.head == self.tail {
            self.status = RingBufferStatus::Empty;
        }
        c
    }

    /// Get the length of remaining data in the buffer
    const fn available_read(&self) -> usize {
        if matches!(self.status, RingBufferStatus::Empty) {
            0
        } else if self.tail > self.head {
            self.tail - self.head
        } else {
            self.tail + RING_BUFFER_SIZE - self.head
        }
    }

    /// Get the length of remaining space in the buffer
    const fn available_write(&self, capacity: usize) -> usize {
        capacity.saturating_sub(self.available_read())
    }
}

pub struct Pipe {
    readable: bool,
    nonblocking: AtomicBool,
    buffer: Arc<Mutex<PipeRingBuffer>>,
    capacity: Arc<AtomicUsize>,
    wait_queue: Arc<WaitQueue>,
}

impl Pipe {
    pub fn new() -> (Pipe, Pipe) {
        let buffer = Arc::new(Mutex::new(PipeRingBuffer::new()));
        let capacity = Arc::new(AtomicUsize::new(RING_BUFFER_SIZE));
        let wait_queue = Arc::new(WaitQueue::new());
        let read_end = Pipe {
            readable: true,
            nonblocking: AtomicBool::new(false),
            buffer: buffer.clone(),
            capacity: capacity.clone(),
            wait_queue: wait_queue.clone(),
        };
        let write_end = Pipe {
            readable: false,
            nonblocking: AtomicBool::new(false),
            buffer,
            capacity,
            wait_queue,
        };
        (read_end, write_end)
    }

    pub const fn readable(&self) -> bool {
        self.readable
    }

    pub const fn writable(&self) -> bool {
        !self.readable
    }

    pub fn closed(&self) -> bool {
        Arc::strong_count(&self.buffer) == 1
    }

    pub fn capacity(&self) -> usize {
        self.capacity.load(Ordering::Relaxed)
    }

    pub fn available_read_len(&self) -> usize {
        self.buffer.lock().available_read()
    }

    pub fn available_write_len(&self) -> usize {
        let ring_buffer = self.buffer.lock();
        ring_buffer.available_write(self.capacity())
    }

    pub fn set_capacity(&self, size: usize) -> LinuxResult<usize> {
        if size > i32::MAX as usize {
            return Err(LinuxError::EINVAL);
        }

        let used = self.available_read_len();
        let size = size.max(PAGE_SIZE_4K);
        let new_capacity = size.div_ceil(PAGE_SIZE_4K) * PAGE_SIZE_4K;

        if new_capacity < used {
            return Err(LinuxError::EBUSY);
        }
        if new_capacity > RING_BUFFER_SIZE {
            return Err(LinuxError::EPERM);
        }

        self.capacity.store(new_capacity, Ordering::Relaxed);
        self.wait_queue.notify_all(false);
        Ok(new_capacity)
    }

    /// Write as much as possible to the pipe buffer without blocking.
    /// Returns the number of bytes written.
    pub fn write_available(&self, buf: &[u8]) -> usize {
        let mut ring_buffer = self.buffer.lock();
        let avail = ring_buffer.available_write(self.capacity()).min(buf.len());
        for i in 0..avail {
            ring_buffer.write_byte(buf[i]);
        }
        if avail > 0 {
            self.wait_queue.notify_all(false);
        }
        avail
    }

    fn write_broken_pipe(&self) -> LinuxResult<usize> {
        let curr = current();
        // 中文注释：向已无读端的 pipe 写数据时，需要同时触发 `SIGPIPE`
        // 并让本次写调用以 `EPIPE` 失败。
        StarryTaskExt::of(&curr)
            .thread_data()
            .signal
            .send_signal(SignalInfo::new(Signo::SIGPIPE, SI_KERNEL as _));
        Err(LinuxError::EPIPE)
    }
}

