/// Unix domain socket namespace manager.
///
/// Manages both pathname-based and abstract Unix socket addresses.
pub static UNIX_SOCKET_NAMESPACE: Mutex<BTreeMap<UnixAddr, Arc<UnixSocket>>> = 
    Mutex::new(BTreeMap::new());

/// Persisted pathname entries for Unix domain sockets.
///
/// Pathname Unix sockets should keep occupying their name after `close()`
/// until user space explicitly `unlink()`s the path.
pub static UNIX_SOCKET_PATHS: Mutex<BTreeSet<String>> = Mutex::new(BTreeSet::new());

fn current_ucred() -> ucred {
    let curr = current();
    let ext = StarryTaskExt::of(&curr);
    let proc_data = ext.process_data();
    ucred {
        pid: ext.thread.process().pid(),
        uid: proc_data.euid.load(Ordering::Relaxed),
        gid: proc_data.egid.load(Ordering::Relaxed),
    }
}

/// Unix domain socket.
///
/// Supports SOCK_STREAM and SOCK_DGRAM semantics for local IPC.
pub struct UnixSocket {
    /// Socket type (SOCK_STREAM or SOCK_DGRAM)
    pub sock_type: u32,
    /// Bound address (if bound)
    pub bound_addr: Mutex<Option<UnixAddr>>,
    /// Connected peer address (if connected)
    pub peer_addr: Mutex<Option<UnixAddr>>,
    /// Connected peer socket (for socketpair stream semantics)
    pub peer_socket: Mutex<Option<Arc<UnixSocket>>>,
    /// 对端进程凭据，仅在已建立的 stream 连接上有效
    pub peer_cred: Mutex<Option<ucred>>,
    /// 是否处于监听状态
    listening: AtomicBool,
    /// stream 监听 socket 的待 accept 队列
    accept_queue: Mutex<VecDeque<Arc<UnixSocket>>>,
    /// accept 等待队列
    accept_wq: WaitQueue,
    /// Receive buffer (for datagram sockets)
    pub recv_buffer: Mutex<VecDeque<(Vec<u8>, UnixAddr)>>,
    /// Receiver wait queue
    pub recv_wq: WaitQueue,
    /// Non-blocking flag
    pub nonblocking: AtomicBool,
}

impl UnixSocket {
    /// Creates a new Unix socket.
    pub fn new(sock_type: u32) -> Self {
        Self {
            sock_type,
            bound_addr: Mutex::new(None),
            peer_addr: Mutex::new(None),
            peer_socket: Mutex::new(None),
            peer_cred: Mutex::new(None),
            listening: AtomicBool::new(false),
            accept_queue: Mutex::new(VecDeque::new()),
            accept_wq: WaitQueue::new(),
            recv_buffer: Mutex::new(VecDeque::new()),
            recv_wq: WaitQueue::new(),
            nonblocking: AtomicBool::new(false),
        }
    }

    /// Creates a connected Unix socket pair.
    pub fn new_pair(sock_type: u32) -> (Self, Self) {
        let left = Self::new(sock_type);
        let right = Self::new(sock_type);
        (left, right)
    }

    fn ensure_pathname_entry(path: &str) -> LinuxResult {
        // pathname Unix socket 这里不依赖真实 VFS 文件节点，
        // 只借助 VFS 做路径合法性校验，并在内核里登记这个名字。
        with_fs(AT_FDCWD as _, |fs| {
            let addr = UnixAddr::new_pathname(path.into());
            let occupied = UNIX_SOCKET_NAMESPACE.lock().contains_key(&addr);
            let mut paths = UNIX_SOCKET_PATHS.lock();
            if paths.contains(path) {
                if occupied {
                    return Err(LinuxError::EADDRINUSE);
                }
                // 上一轮异常退出可能遗留了只占名、没有活跃 socket 的陈旧条目。
                paths.remove(path);
            }
            if fs.resolve_no_follow(path).is_ok() {
                return Err(LinuxError::EADDRINUSE);
            }
            fs.resolve_nonexistent(path.into())?;
            paths.insert(path.into());
            Ok(())
        })
    }

    pub fn unlink_path(path: &str) -> bool {
        let removed = UNIX_SOCKET_PATHS.lock().remove(path);
        if removed {
            UNIX_SOCKET_NAMESPACE
                .lock()
                .remove(&UnixAddr::new_pathname(path.into()));
        }
        removed
    }

    /// Binds the socket to a Unix address.
    pub fn bind(self: &Arc<Self>, addr: UnixAddr) -> LinuxResult {
        if let UnixAddr::Pathname(path) = &addr {
            Self::ensure_pathname_entry(path)?;
        }

        // 先完成 pathname 合法性检查，再统一拿 namespace 锁登记，
        // 避免在 ensure_pathname_entry() 内外重复拿同一把锁造成卡死。
        let mut namespace = UNIX_SOCKET_NAMESPACE.lock();
        if namespace.contains_key(&addr) {
            return Err(LinuxError::EADDRINUSE);
        }

        // Register in namespace
        namespace.insert(addr.clone(), self.clone());

        // Set bound address
        *self.bound_addr.lock() = Some(addr);

        Ok(())
    }

    /// Connects to another Unix socket.
    pub fn connect(self: &Arc<Self>, addr: UnixAddr) -> LinuxResult {
        let peer = {
            let namespace = UNIX_SOCKET_NAMESPACE.lock();
            namespace.get(&addr).cloned()
        };

        if let Some(peer) = peer {
            if self.sock_type == SOCK_STREAM {
                if !peer.is_listening() {
                    return Err(LinuxError::ECONNREFUSED);
                }

                let accepted = Arc::new(Self::new(self.sock_type));
                // 中文注释：AF_UNIX stream 在 connect 时直接生成服务端的已连接 socket，
                // 由监听端后续 `accept()` 取走，先满足 getsockopt02 所需的最小语义。
                *accepted.bound_addr.lock() = peer.bound_addr.lock().clone();
                *accepted.peer_addr.lock() = Some(
                    self.bound_addr
                        .lock()
                        .clone()
                        .unwrap_or_else(|| UnixAddr::Abstract(vec![])),
                );
                *accepted.peer_socket.lock() = Some(self.clone());
                *accepted.peer_cred.lock() = Some(current_ucred());

                *self.peer_addr.lock() = Some(addr);
                *self.peer_socket.lock() = Some(accepted.clone());

                peer.accept_queue.lock().push_back(accepted);
                peer.accept_wq.notify_one(true);
                return Ok(());
            }

            // Set peer address
            *self.peer_addr.lock() = Some(addr);
            return Ok(());
        }

        if let UnixAddr::Pathname(path) = &addr {
            if UNIX_SOCKET_PATHS.lock().contains(path) {
                // 中文注释：pathname 已经被某个 Unix socket 占名，但当前没有活跃监听者，
                // 这种情况要表现成“连接被拒绝”，而不是“路径不存在”。
                return Err(LinuxError::ECONNREFUSED);
            }

            // 中文注释：musl 在查 nscd 时会用一个较短的 sockaddr_un 去 connect。
            // 如果目标路径根本不存在，Linux 应返回 ENOENT/ENOTDIR 这类路径错误，
            // 不能直接吞成 EINVAL/ECONNREFUSED，否则用户态会把组查询判成致命失败。
            return with_fs(AT_FDCWD as _, |fs| match fs.resolve_no_follow(path) {
                Ok(_) => Err(LinuxError::ECONNREFUSED),
                Err(err) => Err(err.into()),
            });
        }

