use axsignal::Signo;
use bitflags::bitflags;
use linux_raw_sys::general::{
    __WALL, __WCLONE, __WNOTHREAD, WCONTINUED, WEXITED, WNOHANG, WNOWAIT, WUNTRACED,
};
use starry_core::task::{ProcessData, StarryTaskExt};

use crate::ptr::{UserPtr, nullable};

bitflags! {
    #[derive(Debug)]
    struct WaitOptions: u32 {
        /// Do not block when there are no processes wishing to report status.
        const WNOHANG = WNOHANG;
        /// Report the status of selected processes which are stopped due to a
        /// `SIGTTIN`, `SIGTTOU`, `SIGTSTP`, or `SIGSTOP` signal.
        const WUNTRACED = WUNTRACED;
        /// Report the status of selected processes which have terminated.
        const WEXITED = WEXITED;
        /// Report the status of selected processes that have continued from a
        /// job control stop by receiving a `SIGCONT` signal.
        const WCONTINUED = WCONTINUED;
        /// Don't reap, just poll status.
        const WNOWAIT = WNOWAIT;

        /// Don't wait on children of other threads in this group
        const WNOTHREAD = __WNOTHREAD;
        /// Wait on all children, regardless of type
        const WALL = __WALL;
        /// Wait for "clone" children only.
        const WCLONE = __WCLONE;
    }
}

#[derive(Debug, Clone, Copy)]
enum WaitPid {
    /// Wait for any child process
    Any,
    /// Wait for the child whose process ID is equal to the value.
    Pid(Pid),
    /// Wait for any child process whose process group ID is equal to the value.
    Pgid(Pid),
}

impl WaitPid {
    fn apply(&self, child: &Process) -> bool {
        match self {
            WaitPid::Any => true,
            WaitPid::Pid(pid) => child.pid() == *pid,
            WaitPid::Pgid(pgid) => child.group().pgid() == *pgid,
        }
    }
}

fn encode_stopped_status(signo: Signo) -> i32 {
    0x7f | ((signo as i32) << 8)
}

fn take_waitable_stopped_child<'a>(
    children: &'a [alloc::sync::Arc<Process>],
    consume: bool,
) -> Option<(&'a alloc::sync::Arc<Process>, Signo)> {
    children.iter().find_map(|child| {
        child.data::<ProcessData>().and_then(|data| {
            data.waitable_stop_signal(consume)
                .map(|signo| (child, signo))
        })
    })
}

pub fn sys_waitpid(pid: i32, exit_code_ptr: UserPtr<i32>, options: u32) -> LinuxResult<isize> {
    let options = WaitOptions::from_bits(options).ok_or(LinuxError::EINVAL)?;
    info!("sys_waitpid <= pid: {:?}, options: {:?}", pid, options);

    let curr = current();
    let ext = StarryTaskExt::of(&curr);
    let process = ext.thread.process();
    let process_data = ext.process_data();

    if pid == i32::MIN {
        // 中文注释：`waitpid(INT_MIN, ...)` 在 Linux 上会因为无法取相反数而返回 `ESRCH`。
        return Err(LinuxError::ESRCH);
    }

    let pid = if pid == -1 {
        WaitPid::Any
    } else if pid == 0 {
        WaitPid::Pgid(process.group().pgid())
    } else if pid > 0 {
        WaitPid::Pid(pid as _)
    } else {
        WaitPid::Pgid(-pid as _)
    };

    let children = process
        .children()
        .into_iter()
        .filter(|child| pid.apply(child))
        .filter(|child| {
            options.contains(WaitOptions::WALL)
                || (options.contains(WaitOptions::WCLONE)
                    == child.data::<ProcessData>().unwrap().is_clone_child())
        })
        .collect::<Vec<_>>();
    if children.is_empty() {
        return Err(LinuxError::ECHILD);
    }

    let exit_code = nullable!(exit_code_ptr.get_as_mut())?;
    loop {
        if options.contains(WaitOptions::WUNTRACED)
            && let Some((child, signo)) =
                take_waitable_stopped_child(&children, !options.contains(WaitOptions::WNOWAIT))
        {
            if let Some(exit_code) = exit_code {
                *exit_code = encode_stopped_status(signo);
            }
            return Ok(child.pid() as _);
        }
        if let Some(child) = children.iter().find(|child| child.is_zombie()) {
            if !options.contains(WaitOptions::WNOWAIT) {
                child.free();
            }
            if let Some(exit_code) = exit_code {
                *exit_code = child.exit_code();
            }
            return Ok(child.pid() as _);
        } else if options.contains(WaitOptions::WNOHANG) {
            axtask::yield_now();
            return Ok(0);
        } else {
            process_data.child_exit_wq.wait();
        }
    }
}

