        x if x == membarrier_cmd::MEMBARRIER_CMD_QUERY as u32 => {
            Ok(SUPPORTED_MEMBARRIER_COMMANDS as isize)
        }
        x if x == membarrier_cmd::MEMBARRIER_CMD_PRIVATE_EXPEDITED as u32
            || x == membarrier_cmd::MEMBARRIER_CMD_REGISTER_PRIVATE_EXPEDITED as u32
            || x == membarrier_cmd::MEMBARRIER_CMD_PRIVATE_EXPEDITED_SYNC_CORE as u32
            || x == membarrier_cmd::MEMBARRIER_CMD_REGISTER_PRIVATE_EXPEDITED_SYNC_CORE as u32
            || x == membarrier_cmd::MEMBARRIER_CMD_PRIVATE_EXPEDITED_RSEQ as u32
            || x == membarrier_cmd::MEMBARRIER_CMD_REGISTER_PRIVATE_EXPEDITED_RSEQ as u32 =>
        {
            // 中文注释：当前内核没有跨 CPU 内存屏障需求，线程库这里只需要
