pub fn sys_getgroups(size: usize, list: UserPtr<u32>) -> LinuxResult<isize> {
    let curr = current();
    let proc_data = StarryTaskExt::of(&curr).process_data();
    let supplementary = proc_data.supplementary_gids.read();
    let group_count = supplementary.len();

    if size == 0 {
        return Ok(group_count as isize);
    }
    if size < group_count {
        return Err(LinuxError::EINVAL);
    }

    // 中文注释：Linux 允许先用 size=0 询问长度，再分配足够的用户缓冲区取回补充组。
    let user_groups = list.get_as_mut_slice(group_count)?;
    user_groups.copy_from_slice(&supplementary);
    Ok(group_count as isize)
}

pub fn sys_setgroups(size: usize, list: UserPtr<u32>) -> LinuxResult<isize> {
    let curr = current();
    let proc_data = StarryTaskExt::of(&curr).process_data();

    if proc_data.euid.load(core::sync::atomic::Ordering::Relaxed) != 0 {
        return Err(LinuxError::EPERM);
    }
    if size > NGROUPS_MAX {
        return Err(LinuxError::EINVAL);
    }

    let groups = if size == 0 {
        &[][..]
    } else {
        list.get_as_mut_slice(size)?
    };

    // 中文注释：这里按 Linux 语义只更新补充组列表，不改 real/effective/saved gid。
    let mut supplementary = proc_data.supplementary_gids.write();
    supplementary.clear();
    supplementary.extend_from_slice(groups);
    Ok(0)
}

pub fn sys_setuid(uid: u32) -> LinuxResult<isize> {
    debug!("sys_setuid <= uid: {}", uid);
    let curr = current();
    let proc_data = StarryTaskExt::of(&curr).process_data();
    let euid = proc_data.euid.load(core::sync::atomic::Ordering::Relaxed);

    // Only root (euid=0) can set uid to any value
    // Non-root users can only set uid to their current uid, euid, or suid
    if euid == 0 {
        proc_data.uid.store(uid, core::sync::atomic::Ordering::Relaxed);
        proc_data.euid.store(uid, core::sync::atomic::Ordering::Relaxed);
        proc_data.suid.store(uid, core::sync::atomic::Ordering::Relaxed);
    } else {
        let current_uid = proc_data.uid.load(core::sync::atomic::Ordering::Relaxed);
        let current_suid = proc_data.suid.load(core::sync::atomic::Ordering::Relaxed);
        if uid != euid && uid != current_uid && uid != current_suid {
            return Err(LinuxError::EPERM);
        }
        proc_data.euid.store(uid, core::sync::atomic::Ordering::Relaxed);
    }
    Ok(0)
}

