    ts: UserPtr<timespec>,
) -> LinuxResult<isize> {
    // 先校验 clock_id，避免非法时钟被误当成成功。
    let now = match clock_id as u32 {
        CLOCK_REALTIME => wall_time(),
        CLOCK_MONOTONIC => monotonic_time(),
        CLOCK_REALTIME_COARSE | CLOCK_REALTIME_ALARM => wall_time(),
        CLOCK_MONOTONIC_COARSE | CLOCK_MONOTONIC_RAW | CLOCK_BOOTTIME | CLOCK_BOOTTIME_ALARM => {
            monotonic_time()
        }
        CLOCK_PROCESS_CPUTIME_ID | CLOCK_THREAD_CPUTIME_ID => {
            let (utime, stime) = StarryTaskExt::of(&current())
                .thread_data()
                .time
                .borrow()
                .output();
            utime + stime
        }
        _ => {
            warn!(
                "Called sys_clock_gettime for unsupported clock {}",
                clock_id
            );
            return Err(LinuxError::EINVAL);
        }
    };
    *ts.get_as_mut()? = timespec::from_time_value(now);
    Ok(0)
}

pub fn sys_gettimeofday(ts: UserPtr<timeval>, tz: UserPtr<timezone>) -> LinuxResult<isize> {
    if let Some(ts) = nullable!(ts.get_as_mut())? {
        *ts = timeval::from_time_value(wall_time());
    }
    // 中文注释：`timezone` 参数虽然早已废弃，但 Linux 仍会在它非空时先做
    // 一次用户地址可访问性校验；LTP 会用非法 tz 指针检查这里是否返回 `EFAULT`。
    let _ = nullable!(tz.get_as_mut())?;
    Ok(0)
}

pub fn sys_clock_getres(
    clock_id: __kernel_clockid_t,
    res: UserPtr<timespec>,
) -> LinuxResult<isize> {
    // LTP 会用多种合法 clock_id 调用 clock_getres()，这里只需保证：
    // 1. 合法 clock 成功返回；
    // 2. 非法 clock 返回 EINVAL。
    match clock_id as u32 {
        CLOCK_REALTIME
        | CLOCK_MONOTONIC
        | CLOCK_PROCESS_CPUTIME_ID
        | CLOCK_THREAD_CPUTIME_ID
        | CLOCK_MONOTONIC_RAW
        | CLOCK_REALTIME_COARSE
        | CLOCK_MONOTONIC_COARSE
        | CLOCK_BOOTTIME
        | CLOCK_REALTIME_ALARM
        | CLOCK_BOOTTIME_ALARM => {}
        _ => {
            warn!("Called sys_clock_getres for unsupported clock {}", clock_id);
            return Err(LinuxError::EINVAL);
        }
    }
    if let Some(res) = nullable!(res.get_as_mut())? {
        *res = timespec::from_time_value(TimeValue::from_micros(1));
    }
    Ok(0)
}

#[repr(C)]
pub struct Tms {
    /// user time
    tms_utime: usize,
    /// system time
    tms_stime: usize,
    /// user time of children
    tms_cutime: usize,
    /// system time of children
    tms_cstime: usize,
}

pub fn sys_times(tms: UserPtr<Tms>) -> LinuxResult<isize> {
    let (utime, stime) = StarryTaskExt::of(&current())
        .thread_data()
        .time
        .borrow()
        .output();
    let utime = utime.as_micros() as usize;
    let stime = stime.as_micros() as usize;
    *tms.get_as_mut()? = Tms {
        tms_utime: utime,
        tms_stime: stime,
        tms_cutime: utime,
        tms_cstime: stime,
    };
    Ok(nanos_to_ticks(monotonic_time_nanos()) as _)
}

pub fn sys_getitimer(which: i32, value: UserPtr<itimerval>) -> LinuxResult<isize> {
    let ty = ITimerType::from_repr(which).ok_or(LinuxError::EINVAL)?;
    let (it_interval, it_value) = StarryTaskExt::of(&current())
        .thread_data()
        .time
        .borrow()
        .get_itimer(ty);

    *value.get_as_mut()? = itimerval {
        it_interval: timeval::from_time_value(it_interval),
        it_value: timeval::from_time_value(it_value),
    };
    Ok(0)
}

pub fn sys_setitimer(
    which: i32,
    new_value: UserConstPtr<itimerval>,
    old_value: UserPtr<itimerval>,
) -> LinuxResult<isize> {
    let ty = ITimerType::from_repr(which).ok_or(LinuxError::EINVAL)?;
    let curr = current();

    let (interval, remained) = match nullable!(new_value.get_as_ref())? {
        Some(new_value) => (
            new_value.it_interval.try_into_time_value()?.as_nanos() as usize,
            new_value.it_value.try_into_time_value()?.as_nanos() as usize,
        ),
        None => (0, 0),
    };
    let old = StarryTaskExt::of(&curr)
        .thread_data()
        .time
        .borrow_mut()
        .set_itimer(ty, interval, remained);

    if let Some(old_value) = nullable!(old_value.get_as_mut())? {
        old_value.it_interval = timeval::from_time_value(old.0);
        old_value.it_value = timeval::from_time_value(old.1);
    }
    Ok(0)
}

pub fn sys_timerfd_create(clockid: i32, flags: i32) -> LinuxResult<isize> {
    const VALID_CLOCKS: &[u32] = &[CLOCK_REALTIME, CLOCK_MONOTONIC];
    let valid_flags: u32 = (TFD_CLOEXEC | TFD_NONBLOCK) as u32;

    if !VALID_CLOCKS.contains(&(clockid as u32)) {
        return Err(LinuxError::EINVAL);
    }
    if (flags as u32 & !valid_flags) != 0 {
        return Err(LinuxError::EINVAL);
    }
    // Timerfd creation not yet implemented
    Err(LinuxError::ENOSYS)
}

