fn align_mlock_range(addr: usize, length: usize) -> LinuxResult<(usize, usize)> {
    if length == 0 {
        return Ok((addr.align_down_4k(), addr.align_down_4k()));
    }
    let start = addr.align_down_4k();
    let end = (addr + length).align_up_4k();
    if end <= start {
        return Err(LinuxError::EINVAL);
    }
    Ok((start, end))
}

fn region_overlaps(a_start: usize, a_end: usize, b_start: usize, b_end: usize) -> bool {
    a_start < b_end && b_start < a_end
}

fn remove_mlock_overlap(ranges: &mut Vec<(usize, usize)>, unmap_start: usize, unmap_end: usize) {
    let mut new_ranges = Vec::with_capacity(ranges.len());
    for &(start, end) in ranges.iter() {
        if !region_overlaps(start, end, unmap_start, unmap_end) {
            new_ranges.push((start, end));
            continue;
        }
        if start < unmap_start {
            new_ranges.push((start, unmap_start));
        }
        if unmap_end < end {
            new_ranges.push((unmap_end, end));
        }
    }
    *ranges = new_ranges;
}

fn add_or_merge_range(ranges: &mut Vec<(usize, usize)>, start: usize, end: usize) {
    if start >= end {
        return;
    }
    let mut new_start = start;
    let mut new_end = end;
    let mut new_ranges = Vec::with_capacity(ranges.len() + 1);
    let mut inserted = false;

    for &(range_start, range_end) in ranges.iter() {
        if range_end < new_start || new_end < range_start {
            if !inserted && new_end < range_start {
                new_ranges.push((new_start, new_end));
                inserted = true;
            }
            new_ranges.push((range_start, range_end));
            continue;
        }
        new_start = new_start.min(range_start);

