/// 返回当前全局 core pattern。
pub fn core_pattern() -> String {
    let pattern = CORE_PATTERN.read();
    if pattern.is_empty() {
        String::from("core")
    } else {
        pattern.clone()
    }
}

/// 更新全局 core pattern。
