};
use linux_raw_sys::net::{
    __kernel_sa_family_t, AF_INET, AF_INET6, AF_UNIX, in_addr, in6_addr, sockaddr, sockaddr_in,
    sockaddr_in6, sockaddr_un, socklen_t,
};

/// Trait to extend [`SocketAddr`] and its variants with methods for reading from and writing to user space.
///
pub trait SocketAddrExt: Sized {
    /// This method attempts to interpret the data pointed to by `addr` with the
    /// given `addrlen` as a valid socket address of the implementing type.
    fn read_from_user(addr: UserConstPtr<sockaddr>, addrlen: socklen_t) -> LinuxResult<Self>;

    /// This method serializes the current socket address instance into the
    /// [`sockaddr`] structure pointed to by `addr` in user space.
    fn write_to_user(&self, addr: UserPtr<sockaddr>) -> LinuxResult<socklen_t>;

    /// This method serializes the current socket address into the user buffer,
    /// but only copies at most `max_len` bytes and still returns the full
    /// encoded length, matching Linux `sockaddr` output semantics.
    fn write_to_user_limited(
        &self,
        addr: UserPtr<sockaddr>,
        max_len: socklen_t,
    ) -> LinuxResult<socklen_t>;

    /// Gets the address family of the socket address.
    fn family(&self) -> u16;

    /// Gets the encoded length of the socket address.
    fn addr_len(&self) -> socklen_t;
}

/// Copies a socket address from user space into a temporary kernel storage.
///
/// This function reads `addrlen` bytes from the user-space pointer `addr` and
/// copies them into a `MaybeUninit<sockaddr>` in kernel memory.
///
#[inline]
fn copy_sockaddr_from_user(
    addr: UserConstPtr<sockaddr>,
    addrlen: socklen_t,
) -> LinuxResult<MaybeUninit<sockaddr>> {
    // 中文注释：用户传进来的 sockaddr 长度可能小于完整结构体，
    // AF_UNIX 很常见地只传到实际 sun_path 结尾。这里先整体清零，
    // 再拷贝已有字节，后面读取未覆盖区域时就不会拿到脏数据。
    let mut storage = MaybeUninit::<sockaddr>::zeroed();
    let src = addr.cast::<u8>().get_as_slice(addrlen as usize)?;
    unsafe {
        core::ptr::copy_nonoverlapping(src.as_ptr(), storage.as_mut_ptr() as *mut u8, src.len())
    };

use alloc::{vec, vec::Vec};
use core::{mem::size_of, slice};
use axerrno::{LinuxError, LinuxResult};
use linux_raw_sys::{
    general::{__kernel_timespec, iovec},
    net::{mmsghdr, msghdr, sockaddr, socklen_t, MSG_ERRQUEUE, MSG_OOB},
};

use crate::{
    file::{FileLike, Socket, UnixSocket},
    ptr::{UserConstPtr, UserPtr, nullable},
    socket::{SocketAddrExt, UnixAddr},
};

fn write_user_value<T>(ptr: UserPtr<T>, value: &T) -> LinuxResult<()> {
    let bytes = unsafe { slice::from_raw_parts((value as *const T).cast::<u8>(), size_of::<T>()) };
    // 中文注释：`loongarch64` 这类架构下，内核不能假设用户地址可直接写；
    // 这里统一走 `UserPtr::write_bytes()`，避免在 PLV0 下直接写用户指针触发页故障。
    ptr.write_bytes(bytes)
}

fn user_ptr_at<T>(base: UserPtr<T>, index: usize) -> UserPtr<T> {
    UserPtr::from(base.address().as_usize() + index * size_of::<T>())
}

fn validate_recv_flags(flags: u32) -> LinuxResult<()> {
    if flags & MSG_OOB != 0 {
        return Err(LinuxError::EINVAL);
    }
    if flags & MSG_ERRQUEUE != 0 {
        return Err(LinuxError::EAGAIN);
    }
    Ok(())
}

fn validate_send_flags(flags: u32) -> LinuxResult<()> {
    if flags & MSG_OOB != 0 {
        return Err(LinuxError::EOPNOTSUPP);
    }
    Ok(())
}

fn read_recvfrom_addrlen(addr: UserPtr<sockaddr>, addrlen: UserPtr<socklen_t>) -> LinuxResult<()> {
    if addr.is_null() {
        return Ok(());
    }
    let Some(addrlen) = nullable!(addrlen.get_as_mut())? else {
        return Err(LinuxError::EFAULT);
    };
    // 中文注释：LTP 会把 `socklen_t` 预先写成 `-1` 来校验参数检查是否在真正收包前生效。
    // 这里按有符号长度看待，负值直接拒绝，避免被当成一个超大的无符号长度继续执行。
    if (*addrlen as i32) < 0 {
        return Err(LinuxError::EINVAL);
    }
    Ok(())
}

fn validate_sendto_addrlen(addr: UserConstPtr<sockaddr>, addrlen: u32) -> LinuxResult<()> {
    if !addr.is_null() && (addrlen as i32) < 0 {
        return Err(LinuxError::EINVAL);
